// 🆕 v6.28.0: WhatsApp Business API — Server-seitiger Versand
// ═══════════════════════════════════════════════════════════════
let _whatsappConfig = null;
async function loadWhatsAppConfig() {
    if (_whatsappConfig !== null) return _whatsappConfig;
    try {
        const snap = await db.ref('settings/whatsapp').once('value');
        const cfg = snap.val() || {};
        _whatsappConfig = {
            enabled: cfg.enabled === true,
            apiToken: cfg.apiToken || null,
            phoneNumberId: cfg.phoneNumberId || null
        };
        return _whatsappConfig;
    } catch (e) {
        console.error('❌ WhatsApp-Config laden fehlgeschlagen:', e.message);
        return { enabled: false, apiToken: null, phoneNumberId: null };
    }
}

async function sendWhatsAppMessage(toPhone, text) {
    const config = await loadWhatsAppConfig();
    if (!config.enabled || !config.apiToken || !config.phoneNumberId) {
        return null; // WhatsApp nicht konfiguriert/aktiviert
    }

    // Telefonnummer formatieren (international ohne +)
    let formattedPhone = String(toPhone).replace(/[\s\-\/\(\)\+]/g, '');
    if (formattedPhone.startsWith('0')) {
        formattedPhone = '49' + formattedPhone.substring(1);
    }

    // Nur Mobilnummern (49-15xx, 49-16xx, 49-17xx) — auch leicht zu lange akzeptieren (KI-Tippfehler)
    if (!formattedPhone.match(/^49(1[5-7]\d{8,11})$/)) {
        console.log(`⚠️ WhatsApp: Keine Mobilnummer: ${formattedPhone}`);
        return null;
    }

    try {
        const resp = await fetch(`https://graph.facebook.com/v22.0/${config.phoneNumberId}/messages`, {
            method: 'POST',
            headers: {
                'Authorization': 'Bearer ' + config.apiToken,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                messaging_product: 'whatsapp',
                to: formattedPhone,
                type: 'text',
                text: { body: text }
            })
        });

        const data = await resp.json();
        if (resp.ok && data.messages && data.messages.length > 0) {
            console.log(`✅ WhatsApp gesendet an ${formattedPhone}: ${data.messages[0].id}`);
            return data.messages[0].id;
        } else {
            console.error('❌ WhatsApp Fehler:', JSON.stringify(data.error || data));
            return null;
        }
    } catch (e) {
        console.error('❌ WhatsApp Exception:', e.message);
        return null;
    }
}

// Hilfsfunktion: Kunden-Mobilnummer für WhatsApp ermitteln
// 🆕 v6.34.2: WhatsApp wa.me Link für Telegram-Nachrichten
function formatWhatsAppLink(phone) {
    if (!phone) return '';
    const clean = String(phone).replace(/[\s\-\/\(\)\+]/g, '');
    const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
    // Nur für Mobilnummern einen WA-Link erzeugen (auch leicht zu lange akzeptieren)
    if (normalized.match(/^49(1[5-7]\d{8,11})$/)) {
        return ` <a href="https://wa.me/${normalized}">💬WA</a>`;
    }
    return '';
}

async function getCustomerWhatsAppNumber(ride) {
    // Priorität: mobilePhone > customerMobile > customerPhone > phone
    const candidates = [
        ride.mobilePhone,
        ride.customerMobile,
        ride.customerPhone,
        ride.phone
    ];

    for (const num of candidates) {
        if (!num) continue;
        const clean = String(num).replace(/[\s\-\/\(\)\+]/g, '');
        const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
        // Nur Mobilnummern
        if (normalized.match(/^49(1[5-7]\d{8,9})$/)) return num;
    }

    // Fallback: CRM-Daten laden wenn customerId vorhanden
    if (ride.customerId) {
        try {
            const custSnap = await db.ref('customers/' + ride.customerId).once('value');
            const cust = custSnap.val();
            if (cust) {
                const crmCandidates = [cust.mobilePhone, cust.phone];
                for (const num of crmCandidates) {
                    if (!num) continue;
                    const clean = String(num).replace(/[\s\-\/\(\)\+]/g, '');
                    const normalized = clean.startsWith('0') ? '49' + clean.substring(1) : clean;
                    if (normalized.match(/^49(1[5-7]\d{8,9})$/)) return num;
                }
            }
        } catch (e) { /* ignore */ }
    }

    return null;
}

// WhatsApp-Kunden-Benachrichtigung senden (Text ohne HTML-Tags)
async function sendCustomerWhatsAppNotification(ride, rideId, type) {
    const phone = await getCustomerWhatsAppNumber(ride);
    if (!phone) return false;

    // 🔧 v6.36.0: Gastname hat Priorität über Hotel/CRM-Name
    const passengerName = ride.guestName || ride.customerName;
    const greeting = passengerName ? `Hallo ${passengerName},\n\n` : '';

    const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
    let message = '';

    if (type === 'booking_confirmed') {
        const driverInfo = ride.driverName ? `\n👤 Fahrer: ${ride.driverName}` : '';
        const vehicleInfo = ride.vehicle ? `\n🚗 Fahrzeug: ${ride.vehicle}${ride.vehiclePlate ? ' (' + ride.vehiclePlate + ')' : ''}` : '';
        message = greeting +
            `🚕 Ihr Taxi ist unterwegs!\n\n` +
            `📍 Von: ${ride.pickup || '?'}\n` +
            `🎯 Nach: ${ride.destination || '?'}\n` +
            `🕐 Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            (ride.price ? `💰 Preis: ca. ${ride.price}€` : '') +
            driverInfo + vehicleInfo +
            `\n\n📲 Fahrt live verfolgen:\n${trackingLink}\n\n` +
            `📞 Bei Fragen: 038378/22022`;

    } else if (type === 'booking_new') {
        message = greeting +
            `✅ Ihre Buchung wurde aufgenommen!\n\n` +
            `📍 Von: ${ride.pickup || '?'}\n` +
            `🎯 Nach: ${ride.destination || '?'}\n` +
            `🕐 Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            (ride.price ? `💰 Preis: ca. ${ride.price}€` : '') +
            `\n\n✅ Sie erhalten Updates sobald ein Fahrer zugewiesen wird.\n\n` +
            `📞 Bei Fragen: 038378/22022`;

    } else if (type === 'cancelled') {
        message = greeting +
            `❌ Ihre Fahrt wurde storniert.\n\n` +
            `📍 Von: ${ride.pickup || '?'}\n` +
            `🎯 Nach: ${ride.destination || '?'}\n\n` +
            `📞 Bei Fragen: 038378/22022`;

    } else if (type === 'driver_assigned') {
        const driverInfo = ride.driverName ? `\n👤 Fahrer: ${ride.driverName}` : '';
        const vehicleInfo = ride.vehicle ? `\n🚗 Fahrzeug: ${ride.vehicle}${ride.vehiclePlate ? ' (' + ride.vehiclePlate + ')' : ''}` : '';
        message = greeting +
            `🚕 Fahrer zugeteilt!\n\n` +
            `📍 Von: ${ride.pickup || '?'}\n` +
            `🎯 Nach: ${ride.destination || '?'}\n` +
            `🕐 Abholung: ${ride.pickupTime || 'Sofort'}\n` +
            driverInfo + vehicleInfo +
            `\n\n📲 Fahrt live verfolgen:\n${trackingLink}\n\n` +
            `📞 Bei Fragen: 038378/22022`;
    }

    if (!message) return false;

    const result = await sendWhatsAppMessage(phone, message);
    if (result) {
        console.log(`📱 WhatsApp-Kunden-Nachricht (${type}) gesendet an: ${phone}`);
        await addTelegramLog('📱', 'whatsapp', `WhatsApp ${type}: ${passengerName || '?'}`, { rideId, phone });
    }
    return !!result;
}

async function answerCallbackQuery(callbackId) {
    const token = await loadBotToken();
    if (!token) return;
    try {
        await fetch(`https://api.telegram.org/bot${token}/answerCallbackQuery`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ callback_query_id: callbackId })
        });
    } catch (err) {
        console.error('answerCallbackQuery fehlgeschlagen:', err.message);
    }
}

async function editTelegramMessage(chatId, messageId, text, extraParams = {}) {
    const token = await loadBotToken();
    if (!token) { console.error('Kein Bot-Token!'); return null; }
    try {
        const resp = await fetch(`https://api.telegram.org/bot${token}/editMessageText`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, message_id: messageId, text, parse_mode: 'HTML', ...extraParams })
        });
        const data = await resp.json();
        if (!data.ok) {
            console.error('editMessageText Fehler:', data.description);
            return await sendTelegramMessage(chatId, text, extraParams);
        }
        return data.result;
    } catch (e) {
        console.error('editMessageText Exception:', e.message);
        return await sendTelegramMessage(chatId, text, extraParams);
    }
}

// Tages-Key für Log-Strukturierung (Berlin-Zeit)
function getTodayLogKey() {
    const now = new Date();
    const berlin = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
    return berlin.toISOString().slice(0, 10); // "2026-03-05"
}

async function addTelegramLog(emoji, chatId, msg, details = null) {
    try {
        const dayKey = getTodayLogKey();
        const logRef = db.ref(`settings/telegram/botlog/${dayKey}`);
        const entry = {
            time: Date.now(),
            emoji, chatId: String(chatId), msg,
            ...(details ? { details: JSON.stringify(details).substring(0, 500) } : {})
        };
        await logRef.push(entry);
        // Tages-Logs auf max 500 pro Tag begrenzen + alte Tage aufräumen (ca. 1 von 20 Aufrufen)
        if (Math.random() < 0.05) {
            trimTelegramLogs(dayKey);
        }
    } catch (e) { /* Log-Fehler ignorieren */ }
    console.log(`${emoji} [${chatId}] ${msg}`);
}

// 🆕 v6.38.61: Entscheidungs-Log — schreibt ins ActivityLog (sichtbar im System-Monitor)
// Gibt den Firebase-Key zurück damit outcome später aktualisiert werden kann
async function logDecision(type, message, data = {}) {
    try {
        const ref = db.ref('activityLog').push();
        await ref.set({
            type: 'decision',
            action: data.outcome || 'pending',
            message,
            timestamp: Date.now(),
            data: {
                query: data.query || null,
                result: data.result || null,
                source: data.source || null,
                score: data.score != null ? data.score : null,
                reason: data.reason || null,
                searchWords: data.searchWords || null,
                outcome: data.outcome || null,
                correction: data.correction || null,
                decisionType: type
            }
        });
        return ref.key;
    } catch (e) { return null; }
}

// Entscheidungs-Ergebnis nachträglich setzen (richtig/falsch/korrektur)
async function updateDecisionOutcome(key, outcome, correction = null) {
    if (!key) return;
    try {
        await db.ref(`activityLog/${key}/data`).update({ outcome, correction });
        await db.ref(`activityLog/${key}`).update({ action: outcome });
    } catch (e) { /* ignore */ }
}

// 🆕 v6.38.31: Lifecycle-Log pro Fahrt — dokumentiert jeden Schritt
async function addRideLog(rideId, icon, action, details = null) {
    if (!rideId) return;
    try {
        const entry = {
            t: Date.now(),
            icon,
            action,
            source: `☁️ Cloud v${CLOUD_FUNCTIONS_VERSION}`,
            device: 'cloud',
            version: CLOUD_FUNCTIONS_VERSION,
            ...(details ? { details: typeof details === 'string' ? details : JSON.stringify(details).substring(0, 800) } : {})
        };
        await db.ref(`rides/${rideId}/lifecycleLog`).push(entry);
    } catch (e) { /* Log-Fehler ignorieren */ }
}

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.44: ZENTRALES FEHLERANALYSE-SYSTEM
// Alle Fehler werden in Firebase gespeichert + Admin wird alarmiert
// ═══════════════════════════════════════════════════════════════

// Schweregrade: 'critical' (Admin-Alert sofort), 'error' (geloggt + täglicher Bericht), 'warning' (nur geloggt)
const _errorRateLimit = {}; // Schutz gegen Endlos-Loops: max 1 Alert pro Funktion pro 5 Min

async function logError(functionName, error, context = {}) {
    const now = Date.now();
    const severity = context.severity || 'error';
    const dayKey = getTodayLogKey();

    const entry = {
        t: now,
        ts: new Date(now).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' }),
        fn: functionName,
        severity,
        msg: error?.message || String(error),
        stack: (error?.stack || '').substring(0, 1000),
        chatId: context.chatId ? String(context.chatId) : null,
        rideId: context.rideId || null,
        data: context.data ? JSON.stringify(context.data).substring(0, 500) : null,
        pendingState: context.pendingState ? JSON.stringify(context.pendingState).substring(0, 300) : null,
        version: CLOUD_FUNCTIONS_VERSION
    };

    // 1. In Firebase speichern: /errorLogs/{datum}/{id}
    try {
        await db.ref(`errorLogs/${dayKey}`).push(entry);
    } catch (e2) {
        console.error('❌ logError: Firebase-Write fehlgeschlagen:', e2.message);
    }

    // 2. Console-Log (für Cloud Logging / GCP)
    const logPrefix = severity === 'critical' ? '🔴 CRITICAL' : (severity === 'warning' ? '⚠️ WARNING' : '❌ ERROR');
    console.error(`${logPrefix} [${functionName}] ${entry.msg}`, entry.stack ? `\n${entry.stack}` : '');

    // 3. Admin-Alert bei kritischen Fehlern (Rate-Limited: max 1 pro 5 Min pro Funktion)
    if (severity === 'critical') {
        const rateKey = `${functionName}_${Math.floor(now / 300000)}`; // 5-Min-Fenster
        if (!_errorRateLimit[rateKey]) {
            _errorRateLimit[rateKey] = true;
            try {
                const alertMsg = `🔴 <b>KRITISCHER FEHLER!</b>\n\n` +
                    `⚙️ <b>Funktion:</b> ${functionName}\n` +
                    `❌ <b>Fehler:</b> ${entry.msg}\n` +
                    (context.chatId ? `💬 <b>Chat:</b> ${context.chatId}\n` : '') +
                    (context.rideId ? `🚕 <b>Fahrt:</b> ${context.rideId}\n` : '') +
                    `🕐 <b>Zeit:</b> ${entry.ts}\n` +
                    `📦 <b>Version:</b> v${CLOUD_FUNCTIONS_VERSION}\n\n` +
                    (entry.stack ? `<pre>${entry.stack.substring(0, 300)}</pre>\n\n` : '') +
                    `💡 <i>Fehlerlog: Firebase → errorLogs/${dayKey}</i>`;
                await sendToAllAdmins(alertMsg);
            } catch (e3) {
                console.error('❌ logError: Admin-Alert fehlgeschlagen:', e3.message);
            }
        }
    }

    // 4. Lifecycle-Log wenn Ride vorhanden
    if (context.rideId) {
        await addRideLog(context.rideId, '❌', `Fehler in ${functionName}: ${entry.msg}`);
    }

    // Cleanup: alte Rate-Limit-Keys entfernen (älter als 10 Min)
    for (const key of Object.keys(_errorRateLimit)) {
        const keyTime = parseInt(key.split('_').pop()) * 300000;
        if (now - keyTime > 600000) delete _errorRateLimit[key];
    }
}

// 🆕 v6.38.44: Daten-Inkonsistenz melden (Strecke fehlt, Preis fehlt, etc.)
async function logDataInconsistency(rideId, ride, issues) {
    const dayKey = getTodayLogKey();
    const entry = {
        t: Date.now(),
        ts: new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' }),
        type: 'data_inconsistency',
        rideId,
        customer: ride?.customerName || '?',
        pickup: ride?.pickup || '?',
        destination: ride?.destination || '?',
        issues,
        version: CLOUD_FUNCTIONS_VERSION
    };

    try {
        await db.ref(`errorLogs/${dayKey}`).push(entry);
    } catch (e) { /* ignore */ }

    // Admin warnen wenn schwerwiegend
    if (issues.length > 0) {
        const warnMsg = `⚠️ <b>DATEN-INKONSISTENZ</b>\n\n` +
            `🚕 Fahrt: <b>${ride?.customerName || '?'}</b>\n` +
            `📍 ${ride?.pickup || '?'} → ${ride?.destination || '?'}\n\n` +
            issues.map(i => `❌ ${i}`).join('\n') +
            `\n\n🔧 <i>Bitte Fahrt prüfen: ${rideId}</i>`;
        try {
            await sendToAllAdmins(warnMsg);
        } catch (e) { /* ignore */ }
        await addRideLog(rideId, '⚠️', `Daten-Inkonsistenz: ${issues.join(', ')}`);
    }
}

// 🆕 v6.38.44: ErrorLogs automatisch aufräumen (max 7 Tage behalten)
async function trimErrorLogs() {
    try {
        const snap = await db.ref('errorLogs').once('value');
        const logs = snap.val();
        if (!logs) return;
        const now = new Date();
        const cutoff = new Date(now);
        cutoff.setDate(cutoff.getDate() - 7);
        const cutoffKey = cutoff.toISOString().slice(0, 10);
        for (const dayKey of Object.keys(logs)) {
            if (dayKey < cutoffKey) {
                await db.ref(`errorLogs/${dayKey}`).remove();
                console.log(`🧹 ErrorLogs gelöscht: ${dayKey}`);
            }
        }
    } catch (e) { /* ignore */ }
}

function trimTelegramLogs(currentDay) {
    const rootRef = db.ref('settings/telegram/botlog');
    rootRef.once('value').then(snap => {
        if (!snap.exists()) return;
        const days = [];
        snap.forEach(dayChild => { days.push(dayChild.key); });
        // Alte Tage löschen (älter als 7 Tage behalten)
        const cutoffDate = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
        for (const day of days) {
            if (day < cutoffDate) {
                rootRef.child(day).remove().catch(() => {});
            }
        }
        // Heutigen Tag auf max 500 Einträge begrenzen
        const todayRef = rootRef.child(currentDay);
        todayRef.once('value').then(todaySnap => {
            const count = todaySnap.numChildren();
            if (count > 520) {
                const toDelete = count - 500;
                let deleted = 0;
                todaySnap.forEach(child => {
                    if (deleted < toDelete) { child.ref.remove(); deleted++; }
                });
            }
        }).catch(() => {});
    }).catch(() => {});
}

