// 🆕 v6.20.0: SERVER-SEITIGE TELEGRAM-BENACHRICHTIGUNGEN
// Firebase Database Triggers — funktionieren OHNE offenen Browser!
// ═══════════════════════════════════════════════════════════════

// Hilfsfunktion: Berlin-Zeit formatieren
function formatBerlinTime(timestamp) {
    const d = new Date(timestamp || Date.now());
    return d.toLocaleString('de-DE', {
        timeZone: 'Europe/Berlin',
        day: '2-digit', month: '2-digit', year: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit'
    });
}

// Hilfsfunktion: Admin-Chats laden und Nachricht senden
// 🔔 v6.20.1: Benachrichtigungs-Kategorien für Admins
const NOTIFY_CATEGORIES = {
    new_ride: { emoji: '🚕', label: 'Neue Buchung', desc: 'Neue Fahrten (Sofort + Vorbestellung)' },
    status_change: { emoji: '🔄', label: 'Status-Änderung', desc: 'Angenommen / Unterwegs / Abgeschlossen' },
    cancellation: { emoji: '⚠️', label: 'Stornierung', desc: 'Kunde storniert Fahrt' },
    ride_deleted: { emoji: '🗑️', label: 'Fahrt gelöscht', desc: 'Fahrt wurde gelöscht' },
    unassigned: { emoji: '🚨', label: 'Offene Fahrt', desc: 'Fahrt ohne Fahrer kurz vor Abholung' },
    change_request: { emoji: '🔔', label: 'Änderungsanfrage', desc: 'Kunde möchte Fahrt ändern' },
    spam_block: { emoji: '🚫', label: 'Spam-Blockierung', desc: 'Nutzer wegen Spam geblockt' },
    optimization: { emoji: '🚀', label: 'Optimierung/Umplanung', desc: 'Fahrt automatisch umgeplant (Schicht, Leerfahrt, Konflikt)' }
};

async function getAdminNotifyPrefs(chatId) {
    try {
        const snap = await db.ref(`settings/telegram/adminNotifyPrefs/${chatId}`).once('value');
        return snap.val() || null; // null = alle aktiv (Standard)
    } catch (e) { return null; }
}

async function sendToAllAdmins(message, category) {
    try {
        const snapshot = await db.ref('settings/telegram/adminChats').once('value');
        const _raw = snapshot.val();
        // 🔧 v6.38.43: Firebase gibt Arrays manchmal als Objekte zurück → normalisieren
        const adminChats = Array.isArray(_raw) ? _raw : (typeof _raw === 'object' && _raw !== null ? Object.values(_raw) : (_raw ? [_raw] : []));
        if (adminChats.length === 0) {
            console.log('⚠️ Keine Telegram-Admin-Chats konfiguriert');
            return;
        }
        console.log(`📢 sendToAllAdmins: ${adminChats.length} Admins, Kategorie: ${category || 'alle'}`);
        for (const chatId of adminChats) {
            // 🔔 v6.20.1: Kategorie-Filter prüfen
            if (category) {
                const prefs = await getAdminNotifyPrefs(chatId);
                if (prefs && prefs[category] === false) {
                    console.log(`🔕 Admin ${chatId}: Kategorie '${category}' deaktiviert`);
                    continue;
                }
            }
            const result = await sendTelegramMessage(chatId, message);
            if (!result) console.error(`❌ sendToAllAdmins: Nachricht an ${chatId} fehlgeschlagen`);
        }
    } catch (e) {
        console.error('❌ sendToAllAdmins Fehler:', e.message, e.stack);
    }
}

// 🔧 v6.26.0: System-Kanal — alle wichtigen Events in einem Telegram-Kanal loggen
let _systemChannelId = null;
async function getSystemChannelId() {
    if (_systemChannelId !== null) return _systemChannelId || null;
    try {
        const snap = await db.ref('settings/telegram/systemChannelId').once('value');
        _systemChannelId = snap.val() || '';
        return _systemChannelId || null;
    } catch (e) {
        return null;
    }
}

async function sendToSystemChannel(message, category) {
    try {
        const channelId = await getSystemChannelId();
        if (!channelId) return;

        // Kategorie-Tag voranstellen für Filterbarkeit
        const tags = {
            'new_ride': '📋',
            'status_change': '🔄',
            'ride_deleted': '🗑️',
            'optimization': '⚙️',
            'unassigned': '🚨',
            'auto_assign': '🤖',
            'payment': '💳',
            'system': '🔧'
        };
        const tag = tags[category] || '📌';
        const taggedMessage = `${tag} <b>[${(category || 'system').toUpperCase()}]</b>\n${message}`;

        await sendTelegramMessage(channelId, taggedMessage);
    } catch (e) {
        console.error('❌ sendToSystemChannel Fehler:', e.message);
    }
}

// Hilfsfunktion: Telegram Chat-ID eines Fahrers ermitteln
async function getDriverChatId(vehicleId) {
    if (!vehicleId) return null;
    try {
        const driverSnap = await db.ref('vehicles/' + vehicleId).once('value');
        const driverData = driverSnap.val();
        if (!driverData) return null;

        // Zuerst: Chat-ID vom User-Account
        if (driverData.userId) {
            const userSnap = await db.ref('users/' + driverData.userId + '/telegramChatId').once('value');
            if (userSnap.val()) return userSnap.val();
        }
        // Fallback: Chat-ID direkt am Fahrzeug
        return driverData.telegramChatId || null;
    } catch (e) {
        console.error('❌ getDriverChatId Fehler:', e.message);
        return null;
    }
}

// Hilfsfunktion: Kunden-Chat-ID ermitteln (Telegram)
async function getCustomerChatId(ride) {
    // 1. Direkt aus der Ride (Telegram-Buchungen)
    if (ride.telegramChatId) return ride.telegramChatId;

    // 2. Über Telefonnummer in /customers suchen
    const phone = ride.customerPhone || ride.phone;
    if (!phone) return null;
    try {
        const customersSnap = await db.ref('customers').orderByChild('phone').equalTo(phone).once('value');
        const customers = customersSnap.val();
        if (customers) {
            for (const id in customers) {
                if (customers[id].telegramChatId) return customers[id].telegramChatId;
            }
        }
    } catch (e) { /* ignore */ }
    return null;
}

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.26.0: SCHEDULED AUTO-ASSIGN — Alle 10 Min unzugewiesene Fahrten zuweisen
// Zentrale Cloud-Zuweisung — funktioniert 24/7 ohne Browser!
// ═══════════════════════════════════════════════════════════════
exports.scheduledAutoAssign = onSchedule(
    {
        schedule: 'every 10 minutes',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '1GiB' // 🔧 v6.38.30: 256/512MB reichte nicht für 5000+ Fahrten
    },
    async (event) => {
        console.log('🎯 v6.38.30: scheduledAutoAssign gestartet...');

        // 🔧 v6.38.36: Einmalige Migration — Kalender-Export-Settings reparieren
        try {
            const _calExpSnap = await db.ref('settings/calendarExport/showPassengers').once('value');
            if (_calExpSnap.val() === false) {
                await db.ref('settings/calendarExport').update({
                    showPassengers: true,
                    showPhone: true,
                    showPickup: true,
                    showDestination: true,
                    showPrice: true
                });
                console.log('✅ v6.38.36: Kalender-Export-Settings repariert (showPassengers/showPhone waren false)');
            }
        } catch(_e) { console.warn('⚠️ CalExport-Fix:', _e.message); }

        try {
            // 🔧 v6.38.30: Relevante Fahrten laden (nicht alle 5000+)
            const now = Date.now();
            const [assignedSnap, vorbestelltSnap, newSnap, vehiclesSnap, shiftsSnap, settingsSnap, prioritiesSnap] = await Promise.all([
                db.ref('rides').orderByChild('status').equalTo('assigned').once('value'),
                db.ref('rides').orderByChild('status').equalTo('vorbestellt').once('value'),
                db.ref('rides').orderByChild('status').equalTo('new').once('value'),
                db.ref('vehicles').once('value'),
                db.ref('vehicleShifts').once('value'),
                db.ref('settings/pricing').once('value'),
                db.ref('settings/vehiclePriorities').once('value')
            ]);

            const vehiclesData = vehiclesSnap.val() || {};
            const shiftsData = shiftsSnap.val() || {};
            const pricingSettings = settingsSnap.val() || {};
            const vehiclePriorities = prioritiesSnap.val() || {};
            const priorityAdvantageMin = pricingSettings.priorityAdvantageMinutes || 0;

            // 🆕 v6.38.46: STALE-VEHICLE-CLEANUP — Fahrzeuge ohne GPS-Update > 15 Min offline setzen
            // 🔧 v6.38.50 BUG-13 FIX: NIEMALS Fahrzeuge löschen die auf aktiver Fahrt sind!
            // Sammle alle aktiven Fahrten vorab
            const _allRidesForCleanup = [];
            const _ridesSnapCleanup = await db.ref('rides').once('value');
            if (_ridesSnapCleanup.exists()) _ridesSnapCleanup.forEach(c => { const r = c.val(); if (r) { r._id = c.key; _allRidesForCleanup.push(r); } });

            const STALE_TIMEOUT_MS = 15 * 60 * 1000; // 15 Minuten
            for (const [vid, vData] of Object.entries(vehiclesData)) {
                if (!vData.lastUpdate) continue;
                const ageMs = now - vData.lastUpdate;
                if (ageMs > STALE_TIMEOUT_MS) {
                    // BUG-13 FIX: Prüfe ob Fahrzeug gerade auf einer aktiven Fahrt ist
                    const _hasActiveRide = _allRidesForCleanup.some(r =>
                        (r.vehicleId === vid || r.assignedVehicle === vid) &&
                        ['on_way', 'picked_up', 'assigned', 'accepted'].includes(r.status)
                    );
                    if (_hasActiveRide) {
                        console.log(`🛡️ STALE-CLEANUP: ${(OFFICIAL_VEHICLES[vid] || {}).name || vid} — GPS veraltet aber auf aktiver Fahrt → NICHT löschen`);
                        continue;
                    }

                    const vName = (OFFICIAL_VEHICLES[vid] || {}).name || vid;
                    const ageMin = Math.round(ageMs / 60000);
                    const lastGpsTime = new Date(vData.lastUpdate).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });
                    console.log(`🧹 STALE-CLEANUP: ${vName} — letztes GPS vor ${ageMin} Min → offline setzen`);
                    try {
                        await db.ref('vehicles/' + vid).remove();
                        console.log(`   ✅ ${vName} aus /vehicles entfernt`);
                        // 📋 Im ActivityLog speichern (sichtbar im System-Log)
                        await db.ref('activityLog').push({
                            type: 'system',
                            action: 'stale_cleanup',
                            message: `🧹 Geister-Fahrzeug entfernt: ${vName} — letztes GPS: ${lastGpsTime} (${ageMin} Min alt)`,
                            timestamp: now,
                            vehicle: vid,
                            vehicleName: vName,
                            lastGps: lastGpsTime,
                            ageMinutes: ageMin,
                            hadShift: vData.shift ? vData.shift.status : null,
                            wasOnline: vData.online || false,
                            source: `☁️ Cloud v${CLOUD_FUNCTIONS_VERSION}`
                        });
                    } catch (cleanupErr) {
                        console.error(`   ❌ ${vName} Cleanup-Fehler:`, cleanupErr.message);
                    }
                }
            }
            const lastverteilungMalus = pricingSettings.lastverteilungMalusMinuten || 3;
            const anschlussBonus = pricingSettings.anschlussfahrtBonusMinuten || 5;

            const getVehiclePrio = (vid) => {
                if (vehiclePriorities[vid] !== undefined) return vehiclePriorities[vid];
                return (OFFICIAL_VEHICLES[vid] || {}).priority || 99;
            };

            // Fahrten aus 3 Status-Queries zusammenführen
            const allRides = [];
            assignedSnap.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));
            vorbestelltSnap.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));
            newSnap.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));

            // 🆕 v6.25.5: Zuerst: Falsch zugewiesene Fahrten korrigieren
            // Wenn eine Sofortfahrt auf ein anderes Datum verschoben wurde,
            // muss das Fahrzeug neu geprüft werden
            const berlinNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
            const todayStr = berlinNow.getFullYear() + '-' + String(berlinNow.getMonth()+1).padStart(2,'0') + '-' + String(berlinNow.getDate()).padStart(2,'0');

            // 🔧 v6.38.30: Debug — nur zukünftige zugewiesene Fahrten loggen
            const _futureAssigned = allRides.filter(r => (r.assignedVehicle || r.vehicleId) && r.pickupTimestamp > now && !['deleted','cancelled','storniert','completed'].includes(r.status));
            console.log(`📊 ${allRides.length} Fahrten geladen, ${_futureAssigned.length} zugewiesene in Zukunft`);
            for (const _dbg of _futureAssigned) {
                console.log(`   📋 ${_dbg.firebaseId}: ${_dbg.customerName || '?'} ts=${_dbg.pickupTimestamp} status=${_dbg.status} vId=${JSON.stringify(_dbg.vehicleId)} aV=${JSON.stringify(_dbg.assignedVehicle)}`);
            }

            // 🔧 v6.38.50 BUG-14 FIX: accepted Fahrten NICHT re-assignen
            const needsReassign = allRides.filter(r => {
                if (!r.assignedVehicle && !r.vehicleId) return false;
                if (['deleted','cancelled','storniert','cancelled_pending_driver','completed','on_way','picked_up','accepted'].includes(r.status)) return false;
                if (r.assignmentLocked) return false;
                if (!r.pickupTimestamp || r.pickupTimestamp < now + 5 * 60000) return false;

                // Prüfe: Ist das zugewiesene Fahrzeug zum Abholzeitpunkt im Dienst?
                const vid = r.assignedVehicle || r.vehicleId;
                const pickupBerlin = new Date(new Date(r.pickupTimestamp).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                const pickupDateStr = pickupBerlin.getFullYear() + '-' + String(pickupBerlin.getMonth()+1).padStart(2,'0') + '-' + String(pickupBerlin.getDate()).padStart(2,'0');
                const pickupTimeStr = String(pickupBerlin.getHours()).padStart(2,'0') + ':' + String(pickupBerlin.getMinutes()).padStart(2,'0');

                // 🆕 v6.38.45: Deaktiviertes Fahrzeug → umplanen!
                const _vehData = vehiclesData[vid] || {};
                if (_vehData.active === false || _vehData.deactivated === true) {
                    const vName = (OFFICIAL_VEHICLES[vid]||{}).name || vid;
                    console.log(`🔄 scheduledAutoAssign: ${r.customerName || r.firebaseId} — ${vName} ist DEAKTIVIERT → umplanen!`);
                    return true;
                }

                // 🔧 v6.38.29: Inkonsistenz-Check — wenn assignedVehicle ≠ vehicleId, BEIDE prüfen
                const vid2 = r.vehicleId && r.assignedVehicle && r.vehicleId !== r.assignedVehicle ? r.vehicleId : null;
                if (vid2) {
                    console.log(`⚠️ INKONSISTENZ ${r.customerName || r.firebaseId}: assignedVehicle=${r.assignedVehicle} ≠ vehicleId=${r.vehicleId} — Fahrt braucht Korrektur!`);
                    return true; // Inkonsistente Daten → immer umplanen
                }

                // 🔧 v6.38.27: Vier-Augen-Prinzip — zwei unabhängige Prüfungen
                const _check1 = isVehicleInShift(vid, shiftsData, pickupDateStr, pickupTimeStr);
                const _check2 = verifyVehicleShiftIndependent(vid, shiftsData, pickupDateStr, pickupTimeStr);
                if (!_check1 || !_check2.ok) {
                    const vName = (OFFICIAL_VEHICLES[vid]||{}).name || vid;
                    console.log(`🔄 scheduledAutoAssign: ${r.customerName || r.firebaseId} — ${vName} hat KEINEN Dienst am ${pickupDateStr} ${pickupTimeStr}! (${_check2.reason})`);
                    if (_check1 !== _check2.ok) console.warn(`⚠️ DISKREPANZ ${vName}: isVehicleInShift=${_check1}, verify=${_check2.ok} (${_check2.reason})`);
                    return true;
                }
                return false;
            });

            // Falsche Zuweisungen entfernen → werden dann unten neu zugewiesen
            for (const r of needsReassign) {
                const oldVehicle = (OFFICIAL_VEHICLES[r.assignedVehicle || r.vehicleId] || {}).name || r.vehicle || '?';
                console.log(`🔄 Entferne Fahrzeug ${oldVehicle} von ${r.customerName || r.firebaseId} (kein Dienst zum Abholzeitpunkt)`);
                await db.ref('rides/' + r.firebaseId).update({
                    assignedVehicle: null, vehicleId: null, assignedTo: null,
                    vehicle: null, vehicleLabel: null, vehiclePlate: null,
                    assignedBy: null, assignedAt: null,
                    status: 'vorbestellt',
                    reassignReason: `Fahrzeug ${oldVehicle} hatte keinen Dienst zum Abholzeitpunkt`,
                    reassignedAt: Date.now(),
                    updatedAt: Date.now()
                });
            }
            if (needsReassign.length > 0) {
                console.log(`🔄 ${needsReassign.length} Fahrzeug-Zuweisungen entfernt (kein Dienst)`);
                // Rides neu laden damit die entfernten Zuweisungen berücksichtigt werden
                allRides.length = 0;
                const [_fAssigned, _fVorbestellt, _fNew] = await Promise.all([
                    db.ref('rides').orderByChild('status').equalTo('assigned').once('value'),
                    db.ref('rides').orderByChild('status').equalTo('vorbestellt').once('value'),
                    db.ref('rides').orderByChild('status').equalTo('new').once('value')
                ]);
                _fAssigned.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));
                _fVorbestellt.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));
                _fNew.forEach(c => allRides.push({ ...c.val(), firebaseId: c.key }));
            }

            // Unzugewiesene Fahrten finden
            const unassigned = allRides.filter(r => {
                if (r.assignedVehicle || r.vehicleId) return false;
                if (['deleted','cancelled','storniert','cancelled_pending_driver','completed','on_way','picked_up'].includes(r.status)) return false;
                if (r.assignmentLocked) return false;
                if (!r.pickupTimestamp) return false;
                if (r.pickupTimestamp < now + 5 * 60000) return false;
                return true;
            });

            if (unassigned.length === 0 && needsReassign.length === 0) {
                console.log('✅ scheduledAutoAssign: Keine unzugewiesenen Fahrten');
                return;
            }

            console.log(`🎯 ${unassigned.length} unzugewiesene Fahrt(en) gefunden`);

            // Nach Abholzeit sortieren (früheste zuerst)
            unassigned.sort((a, b) => a.pickupTimestamp - b.pickupTimestamp);

            let assignedCount = 0;
            let failedCount = 0;

            for (const ride of unassigned) {
                const rideId = ride.firebaseId;
                const pickupDate = new Date(ride.pickupTimestamp);
                const berlinPickup = new Date(pickupDate.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                const dateStr = berlinPickup.getFullYear() + '-' + String(berlinPickup.getMonth()+1).padStart(2,'0') + '-' + String(berlinPickup.getDate()).padStart(2,'0');
                const timeStr = String(berlinPickup.getHours()).padStart(2,'0') + ':' + String(berlinPickup.getMinutes()).padStart(2,'0');
                const passengers = ride.passengers || 1;
                const minutesUntilPickup = (ride.pickupTimestamp - now) / 60000;
                const isSofort = minutesUntilPickup <= 60;

                console.log(`\n📋 Fahrt ${rideId}: ${ride.customerName || '?'} | ${dateStr} ${timeStr} | ${passengers} Pax | ${isSofort ? 'SOFORT' : 'Vorbestellung'}`);

                // 🔧 v6.38.34: PFLICHT — Duration muss vorhanden sein!
                if (!ride.duration && !ride.estimatedDuration) {
                    console.warn(`⚠️ scheduledAutoAssign: Fahrt ${rideId} hat KEINE Duration! Versuche Neuberechnung...`);
                    if (ride.pickupLat && ride.destinationLat) {
                        try {
                            const _rr = await calculateTelegramRoutePrice({
                                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
                            });
                            if (_rr && _rr.duration) {
                                console.log(`✅ Route nachberechnet: ${_rr.distance} km, ${_rr.duration} min, ${_rr.price}€`);
                                ride.duration = _rr.duration;
                                ride.estimatedDuration = _rr.duration;
                                ride.distance = _rr.distance;
                                ride.price = _rr.price;
                                await db.ref(`rides/${rideId}`).update({
                                    duration: _rr.duration, estimatedDuration: _rr.duration,
                                    distance: _rr.distance, estimatedDistance: _rr.distance,
                                    price: _rr.price, estimatedPrice: _rr.price
                                });
                            } else {
                                console.error(`❌ scheduledAutoAssign: Route nicht berechenbar für ${rideId} — ÜBERSPRINGE!`);
                                await sendToAllAdmins(`⚠️ <b>Auto-Zuweisung FEHLGESCHLAGEN</b>\n\nFahrt ${ride.customerName || rideId}: Keine Routendaten, OSRM fehlgeschlagen.\n❌ Bitte manuell prüfen!`);
                                failedCount++;
                                continue;
                            }
                        } catch (e) {
                            console.error(`❌ scheduledAutoAssign: Route-Fehler ${rideId}:`, e.message);
                            failedCount++;
                            continue;
                        }
                    } else {
                        console.error(`❌ scheduledAutoAssign: Fahrt ${rideId} — keine Koordinaten, keine Duration — ÜBERSPRINGE!`);
                        failedCount++;
                        continue;
                    }
                }

                // Kandidaten filtern
                const candidates = [];
                const MAX_GPS_AGE = 10 * 60 * 1000;
                const boardingTime = pricingSettings.boardingTime || 2;
                const alightingTime = pricingSettings.alightingTime || 2;
                const bufferMs = (boardingTime + alightingTime) * 60000;
                const mindestAbstandMs = (pricingSettings.mindestAbstandMin || 0) * 60000;

                for (const [vehicleId, info] of Object.entries(OFFICIAL_VEHICLES)) {
                    if (info.capacity < passengers) continue;
                    // 🔧 v6.38.27: Vier-Augen-Prinzip bei Zuweisung
                    const _sc1 = isVehicleInShift(vehicleId, shiftsData, dateStr, timeStr);
                    const _sc2 = verifyVehicleShiftIndependent(vehicleId, shiftsData, dateStr, timeStr);
                    if (!_sc1 || !_sc2.ok) {
                        if (_sc1 !== _sc2.ok) console.warn(`   ⚠️ DISKREPANZ ${info.name}: isVehicleInShift=${_sc1}, verify=${_sc2.ok} (${_sc2.reason})`);
                        console.log(`   ❌ ${info.name}: Kein Dienst (${_sc2.reason})`);
                        continue;
                    }

                    // 🆕 v6.26.0: Schichtende-Prüfung
                    const _sRideDurMin = ride.duration || ride.estimatedDuration || 20;
                    const _sRideEndMs = ride.pickupTimestamp + _sRideDurMin * 60000;
                    const _sRideEndBerlin = new Date(new Date(_sRideEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                    const _sRideEndTimeStr = String(_sRideEndBerlin.getHours()).padStart(2,'0') + ':' + String(_sRideEndBerlin.getMinutes()).padStart(2,'0');
                    const _sShiftEnd = getShiftEndTime(vehicleId, shiftsData, dateStr, timeStr);
                    if (_sShiftEnd && _sRideEndTimeStr > _sShiftEnd) {
                        console.log(`   ❌ ${info.name}: Fahrtende ${_sRideEndTimeStr} > Schichtende ${_sShiftEnd}`);
                        continue;
                    }

                    // Besetzt-Check — nur on_way/picked_up = wirklich unterwegs
                    // 🔧 v6.34.0: FIX — 'assigned' entfernt (Vorbestellung ≠ besetzt)
                    const busy = allRides.some(r =>
                        (r.vehicleId === vehicleId || r.assignedTo === vehicleId || r.assignedVehicle === vehicleId) &&
                        (r.status === 'on_way' || r.status === 'picked_up')
                    );
                    if (busy && isSofort) {
                        console.log(`   ❌ ${info.name}: Aktuell besetzt`);
                        continue;
                    }

                    // Zeitkonflikt prüfen
                    // 🆕 v6.33.8: Rückfahrt zur Basis einrechnen!
                    // 🔧 v6.33.7: Sofortfahrt — kein Rückfahrt-Puffer für die neue Fahrt
                    if (ride.pickupTimestamp) {
                        const newPickup = ride.pickupTimestamp;
                        const newDur = (ride.duration || ride.estimatedDuration || 20) * 60000;
                        const _rueckfahrtMs2 = (pricingSettings.standortRueckkehrPufferMinuten || 30) * 60000;
                        const _newReturnMs2 = isSofort ? 0 : _rueckfahrtMs2;
                        const hasConflict = allRides.some(r => {
                            if (r.firebaseId === rideId) return false;
                            if (r.vehicleId !== vehicleId && r.assignedTo !== vehicleId && r.assignedVehicle !== vehicleId) return false;
                            if (!r.pickupTimestamp) return false;
                            if (['deleted','cancelled','storniert','cancelled_pending_driver','completed'].includes(r.status)) return false;
                            const rDur = (r.duration || r.estimatedDuration || 20) * 60000;
                            // Fahrt belegt = Fahrtdauer + Ein/Aussteigen + Rückfahrt zur Basis
                            const rEnd = r.pickupTimestamp + rDur + bufferMs + _rueckfahrtMs2;
                            const newEnd = newPickup + newDur + bufferMs + _newReturnMs2;
                            return (newPickup < rEnd + mindestAbstandMs) && (r.pickupTimestamp < newEnd + mindestAbstandMs);
                        });
                        if (hasConflict) {
                            console.log(`   ⚠️ ${info.name}: Zeitkonflikt`);
                            continue;
                        }
                    }

                    candidates.push({ vehicleId, name: info.name, priority: getVehiclePrio(vehicleId), telegramChatId: vehiclesData[vehicleId]?.telegramChatId });
                    console.log(`   ✅ ${info.name}: Verfügbar [Prio ${getVehiclePrio(vehicleId)}]`);
                }

                if (candidates.length === 0) {
                    console.log(`   ❌ Kein Fahrzeug verfügbar für ${ride.customerName || rideId}`);
                    failedCount++;
                    continue;
                }

                // Scoring: Leerfahrt + Priorität + Lastverteilung + Anschlussfahrt
                let bestScore = Infinity;
                let bestCandidate = null;
                let bestDrivingTime = 0;
                const vehicleScores = {};

                for (const cand of candidates) {
                    let leerfahrtMin = 0;
                    let routeMethod = 'prio-only';
                    const prio = getVehiclePrio(cand.vehicleId);
                    const prioPenalty = (prio - 1) * priorityAdvantageMin;

                    // Smart Routing berechnen
                    if (ride.pickupCoords?.lat && ride.pickupCoords?.lon) {
                        try {
                            const result = await estimateVehicleLeerfahrt(
                                cand.vehicleId, ride, allRides, vehiclesData, shiftsData, dateStr, pricingSettings
                            );
                            leerfahrtMin = result.durationMin;
                            routeMethod = result.method;
                        } catch(e) {
                            console.warn(`   ⚠️ ${cand.name}: Leerfahrt-Fehler:`, e.message);
                        }
                    }

                    // Lastverteilung
                    const vehicleRideCount = allRides.filter(r =>
                        (r.vehicleId === cand.vehicleId || r.assignedVehicle === cand.vehicleId) &&
                        r.firebaseId !== rideId &&
                        !['deleted','cancelled','storniert','completed'].includes(r.status)
                    ).length;
                    const avgRides = candidates.length > 0
                        ? allRides.filter(r => (r.assignedVehicle || r.vehicleId) && !['deleted','cancelled','storniert','completed'].includes(r.status)).length / Math.max(candidates.length, 1)
                        : 0;
                    const loadPenalty = vehicleRideCount > avgRides
                        ? Math.round((vehicleRideCount - avgRides) * lastverteilungMalus)
                        : 0;

                    // Anschlussfahrt-Bonus
                    const ketteBonus = (routeMethod === 'anschlussfahrt' || routeMethod === 'anschlussfahrt-gps')
                        ? -anschlussBonus : 0;

                    const totalScore = Math.round(leerfahrtMin + prioPenalty + loadPenalty + ketteBonus);

                    vehicleScores[cand.vehicleId] = {
                        status: 'available',
                        leerfahrtMin: Math.round(leerfahrtMin),
                        routeMethod,
                        priorityPenalty: prioPenalty,
                        loadPenalty,
                        vehicleRideCount,
                        anschlussBonus: ketteBonus,
                        totalScore
                    };

                    console.log(`   📊 ${cand.name}: Leerfahrt ${Math.round(leerfahrtMin)} (${routeMethod}) + Prio ${prioPenalty} + Last ${loadPenalty} + Kette ${ketteBonus} = ${totalScore}`);

                    if (totalScore < bestScore) {
                        bestScore = totalScore;
                        bestCandidate = cand;
                        bestDrivingTime = Math.round(leerfahrtMin);
                    }
                }

                if (!bestCandidate) {
                    failedCount++;
                    continue;
                }

                // 🆕 v6.25.5: Verfügbarkeits-Check — kann das Fahrzeug rechtzeitig ankommen?
                const _maxShiftMin = pricingSettings.maxAutoVerschiebungMin || 15;
                let _shiftedPickupTs = null;
                let _shiftInfo = null;

                if (ride.pickupTimestamp) {
                    const _sPrevRides = allRides.filter(r => {
                        if (r.firebaseId === rideId) return false;
                        if (r.vehicleId !== bestCandidate.vehicleId && r.assignedTo !== bestCandidate.vehicleId && r.assignedVehicle !== bestCandidate.vehicleId) return false;
                        if (!r.pickupTimestamp || r.pickupTimestamp >= ride.pickupTimestamp) return false;
                        if (['deleted','cancelled','storniert','cancelled_pending_driver','completed'].includes(r.status)) return false;
                        return true;
                    }).sort((a, b) => b.pickupTimestamp - a.pickupTimestamp);

                    if (_sPrevRides.length > 0) {
                        const _sPrev = _sPrevRides[0];
                        // 🔧 v6.38.34: Kein Fallback! Ohne Duration → 60 Min als Sicherheits-Maximum
                        const _sPrevDurMs = (_sPrev.duration || _sPrev.estimatedDuration || 60) * 60000;
                        // 🔧 v6.38.53: Rückfahrt-Puffer in prevEnd einrechnen (pauschal 5 Min — calcReturnMs nicht verfügbar hier)
                        const _sPrevReturnMs = 5 * 60000;
                        const _sPrevEndMs = _sPrev.pickupTimestamp + _sPrevDurMs + bufferMs + _sPrevReturnMs;
                        const _sLeerfahrtMs = (bestDrivingTime || 10) * 60000;
                        const _sEarliestMs = _sPrevEndMs + _sLeerfahrtMs + mindestAbstandMs;
                        const _sDelayMs = _sEarliestMs - ride.pickupTimestamp;
                        const _sDelayMin = Math.round(_sDelayMs / 60000);

                        if (_sDelayMs > 0) {
                            const _sPrevEndFormatted = new Date(new Date(_sPrevEndMs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' })).toLocaleTimeString('de-DE', {hour:'2-digit',minute:'2-digit'});

                            if (_sDelayMin > _maxShiftMin) {
                                // Zu großer Konflikt → Fahrzeug NICHT zuweisen
                                console.log(`   ❌ v6.25.5: ${bestCandidate.name} kann nicht rechtzeitig (${_sDelayMin} Min zu spät, Max ${_maxShiftMin})`);
                                vehicleScores[bestCandidate.vehicleId].status = 'busy';
                                vehicleScores[bestCandidate.vehicleId].busyUntil = _sPrevEndFormatted;
                                vehicleScores[bestCandidate.vehicleId].overlapMin = _sDelayMin;
                                await db.ref('rides/' + rideId + '/vehicleScores').set(vehicleScores);
                                failedCount++;
                                continue;
                            } else {
                                // Kleiner Konflikt → Abholzeit verschieben
                                _shiftedPickupTs = _sEarliestMs + 2 * 60000;
                                const _sNewTime = new Date(new Date(_shiftedPickupTs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                                const _sNewFormatted = _sNewTime.toLocaleTimeString('de-DE', {hour:'2-digit',minute:'2-digit'});
                                _shiftInfo = {
                                    pickupTimestamp: _shiftedPickupTs,
                                    pickupTime: String(_sNewTime.getHours()).padStart(2,'0') + ':' + String(_sNewTime.getMinutes()).padStart(2,'0'),
                                    pickupTimeShifted: true,
                                    originalPickupTimestamp: ride.pickupTimestamp,
                                    pickupShiftReason: `Fahrzeug ${bestCandidate.name} erst ab ${_sPrevEndFormatted} frei (Vorfahrt)`,
                                    pickupShiftMinutes: _sDelayMin
                                };
                                console.log(`   🔄 v6.25.5: Abholzeit verschoben → ${_sNewFormatted} (+${_sDelayMin} Min)`);
                            }
                        }
                    }
                }

                // Fahrzeug zuweisen
                vehicleScores[bestCandidate.vehicleId].status = 'chosen';
                const bestInfo = OFFICIAL_VEHICLES[bestCandidate.vehicleId] || {};

                const rideUpdate = {
                    status: isSofort ? 'assigned' : 'vorbestellt',
                    assignedTo: bestCandidate.vehicleId,
                    vehicleId: bestCandidate.vehicleId,
                    vehicle: bestCandidate.name,
                    vehicleLabel: bestCandidate.name,
                    assignedVehicleName: bestCandidate.name,
                    assignedVehiclePlate: bestInfo.plate || '',
                    assignedVehicle: bestCandidate.vehicleId,
                    vehiclePlate: bestInfo.plate || '',
                    assignedAt: Date.now(),
                    assignedBy: 'cloud-scheduled-auto-assign',
                    updatedAt: Date.now(),
                    vehicleScores: vehicleScores,
                    drivingTimeToPickup: bestDrivingTime
                };
                // 🆕 v6.25.5: Verschobene Abholzeit eintragen
                if (_shiftInfo) {
                    Object.assign(rideUpdate, _shiftInfo);
                }

                await db.ref('rides/' + rideId).update(rideUpdate);

                // 🆕 v6.38.31: Lifecycle-Log — Fahrzeug zugewiesen
                await addRideLog(rideId, '🚕', `Fahrzeug zugewiesen: ${bestCandidate.name}`, {
                    fahrzeug: bestCandidate.name,
                    fahrzeugId: bestCandidate.vehicleId,
                    score: bestScore,
                    leerfahrt: bestDrivingTime + ' Min',
                    quelle: 'scheduledAutoAssign (Cloud, alle 10 Min)',
                    grund: Object.entries(vehicleScores).filter(([k,v]) => v.status === 'rejected').map(([k,v]) => `${k}: ${v.rejectReason || v.status}`).join(', ').substring(0, 400)
                });

                // allRides aktualisieren für nächste Iteration (damit Zeitkonflikte korrekt sind)
                const rideIdx = allRides.findIndex(r => r.firebaseId === rideId);
                if (rideIdx >= 0) {
                    allRides[rideIdx] = { ...allRides[rideIdx], ...rideUpdate };
                }

                assignedCount++;
                console.log(`   🏆 ${ride.customerName || rideId} → ${bestCandidate.name} (Score: ${bestScore})`);

                // Fahrer per Telegram benachrichtigen
                if (bestCandidate.telegramChatId) {
                    const pickupLabel = ride.pickupTime || timeStr + ' Uhr';
                    await sendTelegramMessage(bestCandidate.telegramChatId,
                        `🚕 <b>${isSofort ? 'NEUE FAHRT!' : '📅 VORBESTELLUNG zugewiesen!'}</b>\n\n` +
                        `📍 <b>Von:</b> ${ride.pickup || '?'}\n` +
                        `🎯 <b>Nach:</b> ${ride.destination || '?'}\n` +
                        `👤 <b>Kunde:</b> ${ride.customerName || '?'}\n` +
                        (ride.customerPhone ? `📱 <b>Tel:</b> ${ride.customerPhone}${formatWhatsAppLink(ride.customerPhone)}\n` : '') +
                        `🕐 <b>Abholung:</b> ${pickupLabel}\n` +
                        (bestDrivingTime > 0 ? `🚗 <b>Anfahrt:</b> ~${bestDrivingTime} Min\n` : '') +
                        `\n💡 <i>Automatisch zugewiesen (Cloud)</i>`
                    );
                }

                // Admin benachrichtigen
                const autoAssignMsg = `🤖 <b>Auto-Zuweisung</b>\n` +
                    `${ride.customerName || '?'} (${timeStr}) → ${bestCandidate.name}\n` +
                    `Score: ${bestScore} | Leerfahrt: ${bestDrivingTime} Min`;
                await sendToAllAdmins(autoAssignMsg);
                await sendToSystemChannel(autoAssignMsg, 'auto_assign');
            }

            console.log(`\n✅ scheduledAutoAssign abgeschlossen: ${assignedCount} zugewiesen, ${failedCount} ohne Fahrzeug`);

        } catch (err) {
            console.error('❌ scheduledAutoAssign Fehler:', err);
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// TRIGGER 1: Neue Fahrt erstellt → Admin-Benachrichtigung
// ═══════════════════════════════════════════════════════════════
exports.onRideCreated = onValueCreated(
    {
        ref: '/rides/{rideId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const rideId = event.params.rideId;
        const ride = event.data.val();
        if (!ride) return;

        console.log(`📱 onRideCreated: ${rideId} — ${ride.customerName || 'Unbekannt'} — source: ${ride.source || 'browser'}`);

        // Prüfe ob Benachrichtigung schon gesendet wurde (z.B. vom Webhook-Handler selbst)
        if (ride.cloudNotificationSent) {
            console.log('⚠️ Benachrichtigung bereits gesendet (cloudNotificationSent flag)');
            return;
        }

        // 🔧 v6.38.46: Race-Condition-Fix — Browser schreibt Koordinaten NACH dem Erstellen
        // Wenn Koordinaten fehlen, 3 Sekunden warten und nochmal aus Firebase laden
        if (!ride.pickupLat || !ride.destinationLat) {
            console.log(`⏳ onRideCreated: Koordinaten fehlen — warte 3s auf Browser-Nachlieferung...`);
            await new Promise(r => setTimeout(r, 3000));
            const freshSnap = await db.ref('rides/' + rideId).once('value');
            const freshRide = freshSnap.val();
            if (freshRide) {
                // Nur fehlende Felder nachfüllen
                if (!ride.pickupLat && freshRide.pickupLat) { ride.pickupLat = freshRide.pickupLat; ride.pickupLon = freshRide.pickupLon; }
                if (!ride.destinationLat && freshRide.destinationLat) { ride.destinationLat = freshRide.destinationLat; ride.destinationLon = freshRide.destinationLon; }
                if (!ride.duration && freshRide.duration) { ride.duration = freshRide.duration; ride.estimatedDuration = freshRide.estimatedDuration; }
                if (!ride.distance && freshRide.distance) { ride.distance = freshRide.distance; ride.estimatedDistance = freshRide.estimatedDistance; }
                if (!ride.price && freshRide.price) { ride.price = freshRide.price; ride.estimatedPrice = freshRide.estimatedPrice; }
                if (!ride.pickupTimestamp && freshRide.pickupTimestamp) { ride.pickupTimestamp = freshRide.pickupTimestamp; }
                const _fixed = [];
                if (ride.pickupLat && !event.data.val().pickupLat) _fixed.push('Abholort-Koordinaten');
                if (ride.destinationLat && !event.data.val().destinationLat) _fixed.push('Zielort-Koordinaten');
                if (ride.duration && !event.data.val().duration) _fixed.push('Duration');
                if (_fixed.length > 0) {
                    console.log(`✅ onRideCreated: Race-Condition behoben! Nachgeliefert: ${_fixed.join(', ')}`);
                    await addRideLog(rideId, '🔄', `Race-Condition behoben — Daten nachgeladen`, { nachgeliefert: _fixed.join(', '), wartezeit: '3s' });
                } else {
                    console.log(`⚠️ onRideCreated: Nach 3s immer noch keine Koordinaten`);
                }
            }
        }

        // 🔧 v6.38.43: Detailliertes Logging für Debugging
        console.log(`📊 onRideCreated Details: pickup=${ride.pickup}, dest=${ride.destination}, status=${ride.status}, pickupTs=${ride.pickupTimestamp}, pickupLat=${ride.pickupLat}, destLat=${ride.destinationLat}`);

        const timestamp = formatBerlinTime();

        // Zeitformatierung
        const now = Date.now();
        const pickupTs = ride.pickupTimestamp || now;
        const isToday = new Date(pickupTs).toDateString() === new Date(now).toDateString();
        // 🔧 v6.33.4: Sofortfahrt = Abholzeit < 25 Min in der Zukunft (15 Min + 10 Min Anfahrt)
        // isJetzt = explizit "jetzt/sofort" gesagt, ODER keine Abholzeit, ODER < 25 Min
        const anfahrtMin = ride.drivingTimeToPickup || 10;
        const isSofort = ride.isJetzt === true || !ride.pickupTimestamp || (pickupTs - now) < (15 + anfahrtMin) * 60 * 1000;

        let pickupTimeFormatted, statusEmoji, statusText;
        if (isSofort) {
            pickupTimeFormatted = 'SOFORT';
            statusEmoji = '🚕';
            statusText = 'SOFORT-FAHRT!';
        } else if (isToday) {
            pickupTimeFormatted = 'Heute ' + new Date(pickupTs).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });
            statusEmoji = '📅';
            statusText = 'VORBESTELLUNG';
        } else {
            const dateStr = new Date(pickupTs).toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: '2-digit' });
            const timeStr = new Date(pickupTs).toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });
            pickupTimeFormatted = `${dateStr} ${timeStr}`;
            statusEmoji = '📅';
            statusText = 'VORBESTELLUNG';
        }

        // 🆕 v6.34.2: WhatsApp-Link neben Telefonnummer
        const waLink = formatWhatsAppLink(ride.customerPhone || ride.customerMobile || ride.mobilePhone);
        // 🔧 v6.38.17: Firebase gibt Arrays als Objekte zurück → normalisieren
        const _wpRaw = ride.waypoints;
        const _wpArr = Array.isArray(_wpRaw) ? _wpRaw : (typeof _wpRaw === 'object' && _wpRaw !== null ? Object.values(_wpRaw) : []);
        const _wpLines = _wpArr.length > 0
            ? _wpArr.map((wp, i) => `↪️ <b>Stopp ${i + 1}:</b> ${typeof wp === 'string' ? wp : (wp.address || String(wp))}`).join('\n') + '\n'
            : '';
        const message = `${statusEmoji} <b>${statusText}</b>\n` +
            `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
            `📍 <b>Von:</b> ${ride.pickup || '?'}\n` +
            _wpLines +
            `📍 <b>Nach:</b> ${ride.destination || '?'}\n` +
            `👤 <b>Name:</b> ${ride.customerName || '?'}\n` +
            `📱 <b>Tel:</b> ${ride.customerPhone || '?'}${waLink}\n` +
            `🕐 <b>Abholung:</b> ${pickupTimeFormatted}\n` +
            `💰 <b>Preis:</b> ${ride.price || 0}€\n` +
            `⏰ <b>Gesendet:</b> ${timestamp}\n` +
            `\n👉 <a href="https://patrick061977.github.io/taxi-App/">App öffnen</a>`;

        console.log(`📢 onRideCreated: Sende Admin-Benachrichtigung für ${rideId}...`);
        let _adminNotifResult = 'unbekannt';
        try {
            // 🔧 v6.38.45: Admin-Chat-IDs loggen damit man sieht WER benachrichtigt wurde
            const _adminChatsSnap = await db.ref('settings/telegram/adminChats').once('value');
            const _rawAdmChats = _adminChatsSnap.val();
            const _admChatList = Array.isArray(_rawAdmChats) ? _rawAdmChats : (typeof _rawAdmChats === 'object' && _rawAdmChats !== null ? Object.values(_rawAdmChats) : (_rawAdmChats ? [_rawAdmChats] : []));

            await sendToAllAdmins(message, 'new_ride');
            _adminNotifResult = `gesendet an ${_admChatList.length} Admin(s): ${_admChatList.join(', ')}`;
            console.log(`✅ onRideCreated: Admin-Benachrichtigung gesendet für ${rideId} an ${_admChatList.length} Admins`);
        } catch (_notifErr) {
            _adminNotifResult = `FEHLER: ${_notifErr.message}`;
            console.error(`❌ onRideCreated: sendToAllAdmins FEHLER für ${rideId}:`, _notifErr.message, _notifErr.stack);
        }
        await sendToSystemChannel(message, 'new_ride');

        // 🆕 v6.38.96: WhatsApp-Bestätigung an Web-Kunden
        if (ride.source === 'web-booking' && ride.customerPhone) {
            try {
                await sendCustomerWhatsAppNotification(ride, rideId, 'booking_new');
                console.log(`📱 WhatsApp-Bestätigung an Web-Kunden gesendet: ${ride.customerPhone}`);
            } catch (_waErr) {
                console.warn('⚠️ WhatsApp Web-Kunden-Bestätigung Fehler:', _waErr.message);
            }
        }

        // 🔧 v6.38.45: Detailliertes Benachrichtigungs-Log
        await addRideLog(rideId, '📢', `Admin-Benachrichtigung (onRideCreated)`, {
            typ: isSofort ? 'SOFORT' : 'VORBESTELLUNG',
            ergebnis: _adminNotifResult
        });

        // 🆕 v6.38.96: SMS-Queue — Buchungsbestätigung an Kunden senden (via Macrodroid auf Admin-Handy)
        if (ride.customerPhone) {
            try {
                // Nutzt den bestehenden SMS-Toggle aus Admin → Einstellungen → SMS
                const _smsSettingsSnap = await db.ref('settings/sms').once('value');
                const _smsSettings = _smsSettingsSnap.val() || {};
                const _smsEnabled = _smsSettings.bookingEnabled === true;
                if (_smsEnabled) {
                    const _pickupBerlin = new Date(new Date(pickupTs).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                    const _smsDateStr = _pickupBerlin.toLocaleDateString('de-DE', { weekday: 'short', day: '2-digit', month: '2-digit' });
                    const _smsTimeStr = _pickupBerlin.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
                    const _smsPrice = ride.price ? `, ca. ${ride.price}€` : '';
                    const _smsText = isSofort
                        ? `Funk Taxi Heringsdorf: Ihr Taxi kommt! ${ride.pickup || '?'} → ${ride.destination || '?'}${_smsPrice}. Tel: 038378/22022`
                        : `Funk Taxi Heringsdorf: Vorbestellung bestätigt! ${_smsDateStr} ${_smsTimeStr} Uhr, ${ride.pickup || '?'} → ${ride.destination || '?'}${_smsPrice}. Tel: 038378/22022`;

                    await db.ref('smsQueue').push({
                        phone: ride.customerPhone,
                        text: _smsText,
                        rideId: rideId,
                        type: isSofort ? 'sofort_confirmation' : 'vorbestellung_confirmation',
                        status: 'pending',
                        createdAt: Date.now()
                    });
                    console.log(`📲 SMS-Queue: Bestätigung für ${ride.customerPhone} eingetragen`);
                    await addRideLog(rideId, '📲', 'SMS-Bestätigung in Queue', { phone: ride.customerPhone, typ: isSofort ? 'Sofort' : 'Vorbestellung' });
                }
            } catch (_smsErr) {
                console.warn('⚠️ SMS-Queue Fehler:', _smsErr.message);
            }
        }

        // 🔧 v6.38.46: Koordinaten aus pickupCoords/destCoords extrahieren (Browser speichert dort!)
        if (!ride.pickupLat && ride.pickupCoords && ride.pickupCoords.lat) {
            ride.pickupLat = ride.pickupCoords.lat;
            ride.pickupLon = ride.pickupCoords.lon || ride.pickupCoords.lng;
            console.log(`🔧 pickupLat aus pickupCoords extrahiert: ${ride.pickupLat}, ${ride.pickupLon}`);
            // Auch in Firebase nachschreiben damit andere Funktionen es finden
            try { await db.ref(`rides/${rideId}`).update({ pickupLat: ride.pickupLat, pickupLon: ride.pickupLon }); } catch(e) {}
        }
        if (!ride.destinationLat && ride.destCoords && ride.destCoords.lat) {
            ride.destinationLat = ride.destCoords.lat;
            ride.destinationLon = ride.destCoords.lon || ride.destCoords.lng;
            console.log(`🔧 destinationLat aus destCoords extrahiert: ${ride.destinationLat}, ${ride.destinationLon}`);
            try { await db.ref(`rides/${rideId}`).update({ destinationLat: ride.destinationLat, destinationLon: ride.destinationLon }); } catch(e) {}
        }

        // 🔧 v6.38.40: Datenqualitäts-Check — Koordinaten + Duration prüfen
        const _hasPickup = ride.pickupLat && ride.pickupLon;
        const _hasDest = ride.destinationLat && ride.destinationLon;
        const _hasDuration = ride.duration || ride.estimatedDuration;
        const _hasDistance = ride.distance || ride.estimatedDistance;

        if (!_hasPickup || !_hasDest) {
            const _missing = [];
            if (!_hasPickup) _missing.push('Abholort-Koordinaten');
            if (!_hasDest) _missing.push('Zielort-Koordinaten');
            const _warnMsg = `⚠️ <b>FEHLENDE DATEN</b>\n\n` +
                `Fahrt: <b>${ride.customerName || '?'}</b>\n` +
                `📍 ${ride.pickup || '?'} → ${ride.destination || '?'}\n` +
                `🕐 ${pickupTimeFormatted}\n\n` +
                `❌ <b>Fehlend:</b> ${_missing.join(', ')}\n\n` +
                `⚠️ Route kann NICHT berechnet werden!\nBitte Koordinaten manuell prüfen.`;
            await sendToAllAdmins(_warnMsg);
            await addRideLog(rideId, '⚠️', `Fehlende Daten: ${_missing.join(', ')}`, 'Route nicht berechenbar');
            await logDataInconsistency(rideId, ride, _missing.map(m => `${m} fehlt`));
        } else if (!_hasDuration && _hasPickup && _hasDest) {
            // Koordinaten da aber keine Duration → Route nachberechnen
            try {
                const _calcRoute = await calculateTelegramRoutePrice({
                    pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                    destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
                });
                if (_calcRoute && _calcRoute.duration) {
                    await db.ref(`rides/${rideId}`).update({
                        duration: _calcRoute.duration, estimatedDuration: _calcRoute.duration,
                        distance: _calcRoute.distance, estimatedDistance: _calcRoute.distance,
                        ...(!ride.price && _calcRoute.price ? { price: _calcRoute.price, estimatedPrice: _calcRoute.price } : {})
                    });
                    console.log(`✅ onRideCreated: Duration nachberechnet für ${rideId}: ${_calcRoute.duration} min, ${_calcRoute.distance} km`);
                    await addRideLog(rideId, '🔧', `Route nachberechnet: ${_calcRoute.duration} Min, ${_calcRoute.distance} km`, 'Duration fehlte bei Erstellung');
                    // ride-Objekt aktualisieren für spätere Verwendung
                    ride.duration = _calcRoute.duration;
                    ride.distance = _calcRoute.distance;
                }
            } catch(e) {
                await logError('onRideCreated.routeCalc', e, { rideId, severity: 'error' });
            }
        } else if (_hasDuration && _hasPickup && _hasDest) {
            // Duration vorhanden — Plausibilitäts-Check: stimmt die Dauer zur Strecke?
            try {
                const _checkRoute = await calculateTelegramRoutePrice({
                    pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                    destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
                });
                if (_checkRoute && _checkRoute.duration) {
                    const _storedDur = parseInt(ride.duration || ride.estimatedDuration);
                    const _calcDur = parseInt(_checkRoute.duration);
                    const _diff = Math.abs(_storedDur - _calcDur);
                    // Diskrepanz > 10 Min UND > 30% Abweichung → Admin warnen
                    if (_diff > 10 && _diff / _calcDur > 0.3) {
                        const _discMsg = `⚠️ <b>DAUER-DISKREPANZ</b>\n\n` +
                            `Fahrt: <b>${ride.customerName || '?'}</b>\n` +
                            `📍 ${ride.pickup || '?'} → ${ride.destination || '?'}\n\n` +
                            `⏱️ Gespeichert: <b>${_storedDur} Min</b>\n` +
                            `🗺️ OSRM berechnet: <b>${_calcDur} Min</b> (${_checkRoute.distance} km)\n` +
                            `📊 Abweichung: <b>${_diff} Min (${Math.round(_diff / _calcDur * 100)}%)</b>\n\n` +
                            `🔧 Wird automatisch korrigiert!`;
                        await sendToAllAdmins(_discMsg);
                        // Korrigieren
                        await db.ref(`rides/${rideId}`).update({
                            duration: _calcDur, estimatedDuration: _calcDur,
                            distance: _checkRoute.distance, estimatedDistance: _checkRoute.distance
                        });
                        await addRideLog(rideId, '🔧', `Dauer korrigiert: ${_storedDur} → ${_calcDur} Min`, `OSRM: ${_checkRoute.distance} km, ${_calcDur} Min`);
                        ride.duration = _calcDur;
                    }
                }
            } catch(e) {
                await logError('onRideCreated.plausibilityCheck', e, { rideId, severity: 'warning' });
            }
        }

        // 🆕 v6.38.44: Echtzeit-Konsistenz-Prüfung (Strecke fehlt? Preis fehlt? Status falsch?)
        try {
            await validateRideConsistency(rideId, ride);
        } catch (e) {
            await logError('validateRideConsistency', e, { rideId, severity: 'warning' });
        }

        // 🆕 v6.28.0: WhatsApp-Kunden-Benachrichtigung bei neuer Fahrt
        await sendCustomerWhatsAppNotification(ride, rideId, 'booking_new');

        // 🆕 v6.25.5: Kunden-Bestätigung SOFORT bei Erstellung senden (nicht erst bei Update!)
        const customerChatId = await getCustomerChatId(ride);
        if (customerChatId) {
            // 🔧 v6.36.0: Gastname hat Priorität über Hotel/CRM-Name
            const _passengerName = ride.guestName || ride.customerName;
            const _greeting = _passengerName ? `Hallo ${_passengerName},\n\n` : '';
            const vehicleInfo = ride.vehicle ? `\n🚗 <b>Fahrzeug:</b> ${ride.vehicle}${ride.vehiclePlate ? ' (' + ride.vehiclePlate + ')' : ''}` : '';
            const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
            const customerMsg = `🚕 <b>IHRE FAHRT WURDE BESTELLT!</b> 🚕\n\n` +
                _greeting +
                `📍 <b>Von:</b> ${ride.pickup || '?'}\n` +
                `🎯 <b>Nach:</b> ${ride.destination || '?'}\n` +
                `🕐 <b>Abholung:</b> ${pickupTimeFormatted}\n` +
                (ride.price ? `💰 <b>Preis:</b> ca. ${ride.price}€\n` : '') +
                vehicleInfo +
                `\n📲 <b>Fahrt live verfolgen:</b>\n<a href="${trackingLink}">🗺️ Tracking öffnen</a>\n\n` +
                `✅ Sie erhalten Updates sobald der Fahrer losfährt!\n` +
                `📞 Bei Fragen: 038378/22022`;
            // 🔧 v6.38.76: Flag VOR dem Senden setzen — verhindert Race-Condition mit onRideUpdated
            // Vorher: Flag nach dem Senden → onRideUpdated feuerte so schnell dass Flag noch nicht da war → Duplikat
            try { await db.ref('rides/' + rideId + '/customerTelegramSent').set(true); } catch(e) { await logError('onRideCreated.customerTgSent', e, { rideId, severity: 'warning' }); }
            const _custMsgResult = await sendTelegramMessage(customerChatId, customerMsg);
            console.log('📱 Kunden-Bestätigung bei Erstellung gesendet:', customerChatId);
            // 🆕 v6.38.45: Kunden-Benachrichtigung detailliert loggen
            await addRideLog(rideId, '📱', `Kunden-Telegram gesendet`, {
                chatId: String(customerChatId),
                ergebnis: _custMsgResult ? 'gesendet' : 'FEHLGESCHLAGEN',
                kunde: ride.customerName || '?'
            });
        }

        // Flag setzen damit Browser nicht nochmal sendet
        try {
            await db.ref('rides/' + rideId + '/cloudNotificationSent').set(true);
        } catch (e) { await logError('onRideCreated.cloudNotifSent', e, { rideId, severity: 'warning' }); }

        // 🔧 v6.38.46: Auto-Zuweisung für ALLE Fahrten (Sofort + Vorbestellung)
        // 🔧 v6.38.53: Frische Daten aus Firebase lesen (Race-Condition: Telegram-Flow koennte schon zugewiesen haben!)
        let _freshRide = ride;
        try {
            const _freshSnap = await db.ref('rides/' + rideId).once('value');
            _freshRide = _freshSnap.val() || ride;
        } catch(e) { /* Fallback auf Event-Daten */ }
        if (!_freshRide.assignedVehicle && !_freshRide.vehicleId) {
            const _hasCoords = ride.pickupLat && ride.destinationLat;
            // 🔧 v6.38.95: Vorbestellungen NICHT sofort zuweisen — erst 15 Min vorher (scheduledAutoAssign)
            const _isVorbestellung = !isSofort;
            if (_hasCoords && !_isVorbestellung) {
                try {
                    const _zuweisTyp = 'Sofortfahrt';
                    console.log(`🚕 Cloud: Auto-Zuweisung für ${_zuweisTyp} ${rideId}...`);
                    await addRideLog(rideId, '🔍', `Cloud: Suche Fahrzeug (onRideCreated)`, { typ: _zuweisTyp });
                    const assignResult = await autoAssignRide(rideId, ride);
                    if (assignResult && assignResult.vehicleId) {
                        const _assignName = assignResult.name || (OFFICIAL_VEHICLES[assignResult.vehicleId] || {}).name || assignResult.vehicleId;
                        console.log(`✅ Cloud: ${_zuweisTyp} ${rideId} → ${_assignName} zugewiesen`);
                        await addRideLog(rideId, '✅', `Cloud: Fahrzeug zugewiesen (onRideCreated)`, { fahrzeug: _assignName, typ: _zuweisTyp, quelle: 'onRideCreated → autoAssignRide' });
                    } else {
                        console.log(`⚠️ Cloud: Kein Fahrzeug für ${_zuweisTyp} ${rideId} gefunden`);
                        await addRideLog(rideId, '⚠️', `Cloud: Kein Fahrzeug gefunden (onRideCreated)`, { typ: _zuweisTyp, hinweis: isSofort ? 'Kein Fahrer online/verfügbar' : 'scheduledAutoAssign übernimmt' });
                    }
                } catch(e) {
                    console.error(`❌ Cloud: Auto-Zuweisung fehlgeschlagen für ${rideId}:`, e.message);
                    await addRideLog(rideId, '❌', 'Cloud: Auto-Zuweisung Fehler', e.message);
                }
            } else {
                console.log(`⚠️ Cloud: Keine Koordinaten für Auto-Zuweisung von ${rideId}`);
                await addRideLog(rideId, '⚠️', 'Cloud: Auto-Zuweisung übersprungen — keine Koordinaten', { pickupLat: ride.pickupLat || 'fehlt', destLat: ride.destinationLat || 'fehlt' });
            }
        }

        await addTelegramLog('📱', 'cloud', `Neue Fahrt: ${ride.customerName || '?'} (${statusText})`, { rideId });
        console.log(`✅ Admin-Benachrichtigung gesendet für: ${rideId}`);
    }
);

// ═══════════════════════════════════════════════════════════════
// TRIGGER 2: Fahrt aktualisiert → Status-Updates, Fahrer-Benachrichtigung
// ═══════════════════════════════════════════════════════════════
exports.onRideUpdated = onValueUpdated(
    {
        ref: '/rides/{rideId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const rideId = event.params.rideId;
        const before = event.data.before.val();
        const after = event.data.after.val();
        if (!before || !after) return;

        const oldStatus = before.status;
        const newStatus = after.status;
        const oldVehicle = before.assignedVehicle || before.vehicleId;
        const newVehicle = after.assignedVehicle || after.vehicleId;

        // 🆕 v6.25.5: Schicht-Check bei Änderung einer zugewiesenen Fahrt
        // 🔧 v6.38.44: Admin-manuelle Zuweisungen werden NICHT mehr automatisch umgeplant!
        // Nur auto-assigns (cloud-auto-assign, auto-assign, cloud-auto-replan) werden geprüft.
        // Admin kann über "Sperren" Button zusätzlich schützen.
        // 🔧 v6.38.44: Nur automatische Zuweisungen dürfen vom System korrigiert werden
        const _autoAssignSources = ['cloud-auto-assign', 'auto-assign', 'cloud-auto-replan', 'auto-replan', 'cloud-auto-optimize', 'cloud-scheduled-auto-assign'];
        const _isAutoAssign = _autoAssignSources.includes(after.assignedBy);
        // Manuelle Zuweisungen (Admin, Telegram-Admin, qassign, etc.) werden NICHT angefasst
        const _isManualAssign = !_isAutoAssign && after.assignedBy;
        const _skipSchichtCheck = after.assignmentLocked || _isManualAssign;
        if (newVehicle && after.pickupTimestamp && !_skipSchichtCheck) {
            try {
                const shiftsSnap = await db.ref('vehicleShifts').once('value');
                const shiftsData = shiftsSnap.val() || {};
                const pickupBerlin = new Date(new Date(after.pickupTimestamp).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                const pickupDateStr = pickupBerlin.getFullYear() + '-' + String(pickupBerlin.getMonth()+1).padStart(2,'0') + '-' + String(pickupBerlin.getDate()).padStart(2,'0');
                const pickupTimeStr = String(pickupBerlin.getHours()).padStart(2,'0') + ':' + String(pickupBerlin.getMinutes()).padStart(2,'0');

                // Grund 1: Fahrzeug hat keinen Dienst
                const needsReassign_noShift = !isVehicleInShift(newVehicle, shiftsData, pickupDateStr, pickupTimeStr);

                // Grund 2: War Sofortfahrt (GPS), ist jetzt Vorbestellung → neu optimieren
                const minutesUntilPickup = (after.pickupTimestamp - Date.now()) / 60000;
                const wasGpsAssigned = after.assignedBy === 'cloud-auto-assign' || after.assignedBy === 'auto-assign';
                const isNowVorbestellung = minutesUntilPickup > 60;
                const needsReassign_sofortToVorbestellung = wasGpsAssigned && isNowVorbestellung && before.pickupTimestamp !== after.pickupTimestamp;

                if (needsReassign_noShift || needsReassign_sofortToVorbestellung) {
                    const oldVehicleName = (OFFICIAL_VEHICLES[newVehicle] || {}).name || after.vehicle || '?';
                    const reason = needsReassign_noShift
                        ? `${oldVehicleName} hat keinen Dienst am ${pickupDateStr} ${pickupTimeStr}`
                        : `Sofortfahrt → Vorbestellung: Neu-Optimierung (${oldVehicleName} war GPS-basiert)`;
                    console.log(`🔄 onRideUpdated: ${reason}`);
                    await addRideLog(rideId, '🔄', `Fahrzeug entfernt: ${reason}`, { altFahrzeug: oldVehicleName, quelle: 'onRideUpdated Schicht-Check' });
                    await db.ref('rides/' + rideId).update({
                        assignedVehicle: null, vehicleId: null, assignedTo: null,
                        vehicle: null, vehicleLabel: null, vehiclePlate: null,
                        assignedBy: null, assignedAt: null,
                        status: 'vorbestellt',
                        reassignReason: reason,
                        reassignedAt: Date.now(),
                        updatedAt: Date.now()
                    });
                    await autoAssignRide(rideId, { ...after, assignedVehicle: null, vehicleId: null });
                    return;
                }
            } catch(e) { await logError('onRideUpdated.schichtCheck', e, { rideId, severity: 'warning' }); }
        }

        // ─── 🆕 v6.38.55: FELD-ÄNDERUNGEN im Lifecycle-Log tracken ───
        // Nur loggen wenn die Änderung NICHT schon von Telegram-Admin geloggt wurde (editedBy prüfen)
        const _editSource = after.editedBy || 'browser';
        const _skipFieldLog = (after.editedBy === 'telegram-admin' && after.editedAt && (Date.now() - after.editedAt) < 5000);
        if (!_skipFieldLog) {
            if (before.pickup && after.pickup && before.pickup !== after.pickup) {
                await addRideLog(rideId, '✏️', `Abholort: ${before.pickup} → ${after.pickup}`, { field: 'pickup', alt: before.pickup, neu: after.pickup, quelle: _editSource });
            }
            if (before.destination && after.destination && before.destination !== after.destination) {
                await addRideLog(rideId, '✏️', `Zielort: ${before.destination} → ${after.destination}`, { field: 'destination', alt: before.destination, neu: after.destination, quelle: _editSource });
            }
            if (before.pickupTime && after.pickupTime && before.pickupTime !== after.pickupTime) {
                await addRideLog(rideId, '🕐', `Zeit: ${before.pickupTime} → ${after.pickupTime}`, { alt: before.pickupTime, neu: after.pickupTime, quelle: _editSource });
            }
            if (before.customerName && after.customerName && before.customerName !== after.customerName) {
                await addRideLog(rideId, '👤', `Kunde: ${before.customerName} → ${after.customerName}`, { alt: before.customerName, neu: after.customerName, quelle: _editSource });
            }
            if (before.passengers && after.passengers && before.passengers !== after.passengers) {
                await addRideLog(rideId, '👥', `Personen: ${before.passengers} → ${after.passengers}`, { alt: before.passengers, neu: after.passengers, quelle: _editSource });
            }
        }

        // ─── STATUS-ÄNDERUNG → Admin-Benachrichtigung ───
        if (oldStatus !== newStatus) {
            console.log(`📱 onRideUpdated: ${rideId} Status ${oldStatus} → ${newStatus}`);
            // 🆕 v6.38.31: Lifecycle-Log — Status-Änderung
            await addRideLog(rideId, '📊', `Status: ${oldStatus} → ${newStatus}`, { altStatus: oldStatus, neuStatus: newStatus, quelle: 'onRideUpdated' });

            let message = '';
            if (newStatus === 'accepted') {
                message = `✅ <b>FAHRER ZUGEWIESEN!</b>\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                    `🚗 <b>Fahrzeug:</b> ${after.vehicle || 'Unbekannt'}${after.vehiclePlate ? ` (${after.vehiclePlate})` : ''}\n` +
                    `👤 <b>Kunde:</b> ${after.customerName || '?'}\n` +
                    `📱 <b>Tel:</b> ${after.customerPhone || '?'}${formatWhatsAppLink(after.customerPhone || after.customerMobile || after.mobilePhone)}\n` +
                    `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                    `📍 <b>Nach:</b> ${after.destination || '?'}\n` +
                    `💰 <b>Preis:</b> ${after.price || 0}€\n` +
                    `\n👉 <a href="https://patrick061977.github.io/taxi-App/">App öffnen</a>`;

                // Auch Kunden per Telegram benachrichtigen (Bestätigung)
                const customerChatId = await getCustomerChatId(after);
                if (customerChatId) {
                    // 🔧 v6.36.0: Gastname hat Priorität über Hotel/CRM-Name
                    const _passengerName2 = after.guestName || after.customerName;
                    const _greeting2 = _passengerName2 ? `Hallo ${_passengerName2},\n\n` : '';
                    const driverInfo = after.driverName ? `\n👤 <b>Fahrer:</b> ${after.driverName}` : '';
                    const vehicleInfo = after.vehicle ? `\n🚗 <b>Fahrzeug:</b> ${after.vehicle}${after.vehiclePlate ? ' (' + after.vehiclePlate + ')' : ''}` : '';
                    const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
                    const customerMsg = `🚕 <b>IHR TAXI IST UNTERWEGS!</b> 🚕\n\n` +
                        _greeting2 +
                        `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                        `🎯 <b>Nach:</b> ${after.destination || '?'}\n` +
                        `🕐 <b>Abholung:</b> ${after.pickupTime || 'Sofort'}\n` +
                        (after.price ? `💰 <b>Preis:</b> ca. ${after.price}€` : '') +
                        driverInfo + vehicleInfo +
                        `\n\n📲 <b>Fahrt live verfolgen:</b>\n<a href="${trackingLink}">🗺️ Tracking öffnen</a>\n\n` +
                        `📞 Bei Fragen: 038378/22022`;
                    await sendTelegramMessage(customerChatId, customerMsg);
                    console.log('📱 Kunden-Telegram gesendet:', customerChatId);
                }

                // 🆕 v6.28.0: WhatsApp-Benachrichtigung bei Fahrer-Zuweisung
                await sendCustomerWhatsAppNotification(after, rideId, 'booking_confirmed');

            } else if (newStatus === 'storniert' || newStatus === 'cancelled') {
                // 🆕 v6.25.4: Zeige WER und WO storniert hat
                const deletedBy = after.deletedBy || after.cancelledBy || '?';
                let storniertVon = '?';
                if (deletedBy === 'telegram-admin') storniertVon = '📱 Telegram';
                else if (deletedBy === 'admin-browser') storniertVon = '🖥️ Browser';
                else if (deletedBy === 'admin-calendar') storniertVon = '📅 Kalender-Ansicht';
                else if (deletedBy === 'admin-reset') storniertVon = '🔄 Fahrzeug-Reset';
                else if (deletedBy === 'admin-invoice') storniertVon = '🧾 Rechnungs-Ansicht';
                else if (deletedBy.includes('@')) storniertVon = `👤 ${deletedBy}`;
                else if (deletedBy === 'customer-telegram' || deletedBy === 'telegram-customer') storniertVon = '📱 Kunde (Telegram)';
                else if (deletedBy === 'customer-portal') storniertVon = '🌐 Kunde (Portal)';
                else storniertVon = deletedBy;

                // 🆕 v6.38.31: Lifecycle-Log — Stornierung
                await addRideLog(rideId, '🗑️', `STORNIERT von: ${storniertVon}`, { deletedBy, storniertVon, quelle: 'onRideUpdated' });

                message = `🗑️ <b>FAHRT STORNIERT</b>\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                    `👤 <b>Kunde:</b> ${after.customerName || '?'}\n` +
                    `📱 <b>Tel:</b> ${after.customerPhone || '?'}${formatWhatsAppLink(after.customerPhone || after.customerMobile)}\n` +
                    `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                    `📍 <b>Nach:</b> ${after.destination || '?'}\n` +
                    `💰 <b>Preis:</b> ${after.price || 0}€\n` +
                    `\n🔧 <b>Storniert über:</b> ${storniertVon}` +
                    `\n⚠️ Status: Storniert`;

                // Fahrer benachrichtigen falls zugewiesen
                const vehicleId = after.assignedVehicle || after.vehicleId;
                if (vehicleId) {
                    const driverChatId = await getDriverChatId(vehicleId);
                    if (driverChatId) {
                        const cancelMsg = `🚫 <b>FAHRT STORNIERT!</b>\n\n` +
                            `🆔 <b>ID:</b> <code>${rideId}</code>\n` +
                            `👤 <b>Kunde:</b> ${after.customerName || '?'}\n` +
                            `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                            `📍 <b>Nach:</b> ${after.destination || '?'}\n\n` +
                            `⚠️ Diese Fahrt wurde storniert.`;
                        await sendTelegramMessage(driverChatId, cancelMsg);
                        console.log('📱 Stornierung an Fahrer gesendet:', vehicleId);
                    }
                }

                // 🆕 v6.28.0: WhatsApp-Stornierung an Kunden
                await sendCustomerWhatsAppNotification(after, rideId, 'cancelled');

            } else if (newStatus === 'picked_up') {
                message = `🚗 <b>KUNDE ABGEHOLT!</b>\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                    `🚗 <b>Fahrzeug:</b> ${after.vehicle || 'Unbekannt'}\n` +
                    `👤 <b>Kunde:</b> ${after.customerName || '?'}\n` +
                    `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                    `📍 <b>Nach:</b> ${after.destination || '?'}\n` +
                    `💰 <b>Preis:</b> ${after.price || 0}€\n` +
                    `\n🎯 Fahrt zum Ziel läuft...`;

            } else if (newStatus === 'completed') {
                message = `✅ <b>FAHRT ABGESCHLOSSEN!</b>\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                    `🚗 <b>Fahrzeug:</b> ${after.vehicle || 'Unbekannt'}\n` +
                    `👤 <b>Kunde:</b> ${after.customerName || '?'}\n` +
                    `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                    `📍 <b>Nach:</b> ${after.destination || '?'}\n` +
                    `💰 <b>Preis:</b> ${after.price || 0}€\n` +
                    `\n✅ Status: Abgeschlossen`;

                // 🆕 v6.33.7: Anschlussfahrt-Hinweis — Fahrer direkt zum nächsten Abholort schicken
                const completedVehicleId = after.assignedVehicle || after.vehicleId;
                if (completedVehicleId) {
                    try {
                        const pSnap = await db.ref('settings/pricing').once('value');
                        const _pricing = pSnap.val() || {};
                        const anschlussZeitMin = _pricing.anschlussfahrtWeiterfahrtMin ?? 10;

                        // Alle heutigen Fahrten für dieses Fahrzeug laden
                        const ridesSnap = await db.ref('rides').once('value');
                        const allRidesObj = ridesSnap.val() || {};
                        const now = Date.now();

                        // Nächste anstehende Fahrt finden
                        let nextRide = null;
                        let nextRideId = null;
                        for (const [rid, r] of Object.entries(allRidesObj)) {
                            if (rid === rideId) continue;
                            const vId = r.assignedVehicle || r.vehicleId || r.assignedTo;
                            if (vId !== completedVehicleId) continue;
                            if (['deleted','cancelled','storniert','completed','abgeschlossen'].includes(r.status)) continue;
                            if (!r.pickupTimestamp) continue;
                            // Nur Fahrten die in den nächsten X Minuten starten
                            const minutesUntil = (r.pickupTimestamp - now) / 60000;
                            if (minutesUntil > 0 && minutesUntil <= anschlussZeitMin) {
                                if (!nextRide || r.pickupTimestamp < nextRide.pickupTimestamp) {
                                    nextRide = r;
                                    nextRideId = rid;
                                }
                            }
                        }

                        if (nextRide) {
                            const driverChatId = await getDriverChatId(completedVehicleId);
                            if (driverChatId) {
                                const nextTimeStr = new Date(nextRide.pickupTimestamp).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                                const minutesLeft = Math.round((nextRide.pickupTimestamp - now) / 60000);

                                // Anfahrtszeit berechnen (Zielort → nächster Abholort)
                                let anfahrtInfo = '';
                                const destLat = after.destCoords?.lat || after.destinationLat;
                                const destLon = after.destCoords?.lon || after.destinationLon;
                                const nextPickupLat = nextRide.pickupCoords?.lat || nextRide.pickupLat;
                                const nextPickupLon = nextRide.pickupCoords?.lon || nextRide.pickupLon;
                                if (destLat && destLon && nextPickupLat && nextPickupLon) {
                                    const distKm = gpsDistanceKm(destLat, destLon, nextPickupLat, nextPickupLon);
                                    const etaMin = Math.max(1, Math.round((distKm / 50) * 60) + 2);
                                    anfahrtInfo = `\n🚗 <b>Anfahrt:</b> ~${etaMin} Min (${distKm.toFixed(1)} km)`;
                                }

                                const nextMsg = `🔜 <b>ANSCHLUSSFAHRT!</b>\n\n` +
                                    `⏰ <b>In ${minutesLeft} Min</b> (${nextTimeStr} Uhr)\n` +
                                    `👤 <b>Kunde:</b> ${nextRide.customerName || '?'}\n` +
                                    `📍 <b>Abholort:</b> ${nextRide.pickup || '?'}\n` +
                                    `🎯 <b>Ziel:</b> ${nextRide.destination || '?'}` +
                                    anfahrtInfo +
                                    `\n\n➡️ <i>Bitte direkt zum Abholort fahren!</i>`;
                                await sendTelegramMessage(driverChatId, nextMsg);
                                console.log(`🔜 Anschlussfahrt-Hinweis an ${completedVehicleId}: ${nextRide.customerName} in ${minutesLeft} Min`);
                            }
                        }
                    } catch (afErr) {
                        console.error('⚠️ Anschlussfahrt-Check Fehler:', afErr.message);
                    }
                }
            }

            if (message) {
                await sendToAllAdmins(message, 'status_change');
                await sendToSystemChannel(message, 'status_change');
                await addTelegramLog('📱', 'cloud', `Status: ${oldStatus} → ${newStatus} (${after.customerName || '?'})`, { rideId });
                // 🆕 v6.38.95: Status-Wechsel ins buchenLog (System Monitor Dispatch)
                const _stEmoji = { assigned: '🔵', accepted: '🟢', on_way: '🟠', picked_up: '🟣', completed: '✅', cancelled: '❌', storniert: '❌' };
                db.ref('settings/buchenLog').push({
                    time: Date.now(), emoji: _stEmoji[newStatus] || '🔄',
                    msg: `FAHRER: ${oldStatus} → ${newStatus} | ${after.customerName || '?'} | ${after.vehicle || after.assignedVehicle || '?'}`,
                    session: 'cloud'
                }).catch(() => {});
            }

            // 🆕 v6.38.95: KUNDEN-BENACHRICHTIGUNG BEI STATUS-WECHSEL
            // Web-Kunden (buchen.html) und Telegram-Kunden bekommen Updates
            if (newStatus === 'on_way' || newStatus === 'picked_up' || newStatus === 'completed') {
                try {
                    const customerChatId = await getCustomerChatId(after);
                    if (customerChatId) {
                        const _custName = after.guestName || after.customerName || '';
                        const _greeting = _custName ? `Hallo ${_custName},\n\n` : '';
                        const vehicleInfo = after.vehicle ? `\n🚗 <b>Fahrzeug:</b> ${after.vehicle}` : '';
                        const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
                        let custMsg = '';

                        if (newStatus === 'on_way') {
                            custMsg = `🚗 <b>Ihr Fahrer ist unterwegs!</b>\n\n` +
                                _greeting +
                                `📍 Abholung: ${after.pickup || '?'}` +
                                vehicleInfo +
                                `\n\n📲 <a href="${trackingLink}">🗺️ Live-Tracking öffnen</a>\n\n` +
                                `✅ <i>Bitte halten Sie sich bereit!</i>`;
                        } else if (newStatus === 'picked_up') {
                            custMsg = `✅ <b>Sie wurden abgeholt!</b>\n\n` +
                                `🎯 Ziel: ${after.destination || '?'}` +
                                vehicleInfo +
                                `\n\nGute Fahrt! 🚕`;
                        } else if (newStatus === 'completed') {
                            const price = after.finalPrice || after.price || 0;
                            custMsg = `🏁 <b>Fahrt abgeschlossen!</b>\n\n` +
                                _greeting +
                                `📍 ${after.pickup || '?'} → ${after.destination || '?'}\n` +
                                (price ? `💰 <b>Preis:</b> ${price}€\n` : '') +
                                `\n⭐ <i>Vielen Dank für Ihre Fahrt!</i>\n📞 038378 22022`;
                        }

                        if (custMsg) {
                            // Duplikat-Check: nicht doppelt senden
                            const _statusFlag = `customer_${newStatus}_sent`;
                            if (!after[_statusFlag]) {
                                await db.ref('rides/' + rideId + '/' + _statusFlag).set(true);
                                await sendTelegramMessage(customerChatId, custMsg);
                                console.log(`📱 Kunden-Status-Update: ${newStatus} → ${customerChatId}`);
                                await addTelegramLog('📱', 'cloud', `Kunde informiert: ${newStatus} (${after.customerName || '?'})`, { rideId });
                                // 🆕 v6.38.95: Auch ins buchenLog schreiben (System Monitor)
                                const _statusEmoji = { on_way: '🚗', picked_up: '✅', completed: '🏁' };
                                db.ref('settings/buchenLog').push({
                                    time: Date.now(), emoji: _statusEmoji[newStatus] || '📱',
                                    msg: `KUNDE INFORMIERT: ${newStatus} → ${after.customerName || '?'}`,
                                    session: 'cloud'
                                }).catch(() => {});
                            }
                        }
                    }
                } catch (custErr) {
                    console.warn('⚠️ Kunden-Status-Benachrichtigung Fehler:', custErr.message);
                }
            }
        }

        // ─── FAHRER-ZUWEISUNG (neues Fahrzeug) → Fahrer benachrichtigen ───
        if (newVehicle && newVehicle !== oldVehicle && newStatus !== 'storniert' && newStatus !== 'cancelled') {
            console.log(`📱 Fahrer-Zuweisung: ${rideId} → ${newVehicle}`);
            // 🆕 v6.38.31: Lifecycle-Log — Fahrzeug-Wechsel
            const _newVName = (OFFICIAL_VEHICLES[newVehicle] || {}).name || after.vehicle || newVehicle;
            const _oldVName = oldVehicle ? ((OFFICIAL_VEHICLES[oldVehicle] || {}).name || before.vehicle || oldVehicle) : 'keins';
            await addRideLog(rideId, '🚗', `Fahrzeug: ${_oldVName} → ${_newVName}`, { von: _oldVName, nach: _newVName, assignedBy: after.assignedBy || '?', quelle: 'onRideUpdated' });

            // Nur benachrichtigen wenn nicht von autoAssignRide (das macht es selbst)
            if (after.assignedBy !== 'cloud-auto-assign' && after.assignedBy !== 'cloud-auto-replan' && after.assignedBy !== 'cloud-auto-optimize' && after.assignedBy !== 'cloud-scheduled-auto-assign') {
                const driverChatId = await getDriverChatId(newVehicle);
                if (driverChatId) {
                    let customerInfo = `👤 <b>Kunde:</b> ${after.customerName || '?'}`;
                    if (after.guestName) customerInfo += `\n🧳 <b>Fahrgast:</b> ${after.guestName}`;
                    if (after.guestPhone) customerInfo += `\n📱 <b>Fahrgast-Tel:</b> ${after.guestPhone}`;

                    const pickupLabel = after.pickupTime || 'Sofort';
                    const _anfahrt = after.drivingTimeToPickup || 10;
                    const isVorbestellung = after.status === 'vorbestellt' || (after.pickupTimestamp && (after.pickupTimestamp - Date.now()) > (15 + _anfahrt) * 60 * 1000);

                    const driverMsg = `🚨 <b>${isVorbestellung ? '📅 NEUE VORBESTELLUNG!' : 'NEUER AUFTRAG FÜR DICH!'}</b> 🚨\n` +
                        `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                        `📍 <b>Abholung:</b> ${after.pickup || '?'}\n` +
                        `🎯 <b>Ziel:</b> ${after.destination || '?'}\n` +
                        customerInfo + `\n` +
                        `📱 <b>Tel:</b> ${after.customerPhone || '?'}${formatWhatsAppLink(after.customerPhone || after.customerMobile)}\n` +
                        `🕐 <b>Abholung:</b> ${pickupLabel}\n` +
                        `💰 <b>Preis:</b> ${after.price || 0}€\n\n` +
                        (isVorbestellung
                            ? `💡 <i>Fahrt vorgemerkt für ${pickupLabel}</i>`
                            : `⏱️ <b>Du hast 60 SEKUNDEN Zeit!</b>\n👉 <b>JETZT App öffnen und ANNEHMEN!</b>\n<a href="https://patrick061977.github.io/taxi-App/">🚕 App öffnen</a>`);

                    await sendTelegramMessage(driverChatId, driverMsg);
                    console.log('📱 Fahrer-Benachrichtigung gesendet:', newVehicle);
                    await addTelegramLog('📱', 'cloud', `Fahrer benachrichtigt: ${after.vehicle || newVehicle}`, { rideId });
                }
            }

            // Kunden-Buchungsbestätigung bei neuer Zuweisung (nicht bei Stornierung)
            // 🔧 v6.38.95: Wenn Fahrt gerade erst erstellt (<15s), NICHT senden — onRideCreated macht das!
            // Race Condition: autoAssignRide() updatet sofort → onRideUpdated feuert BEVOR onRideCreated fertig
            const _rideAgeMs = after.createdAt ? Date.now() - after.createdAt : Infinity;
            if (!after.customerTelegramSent && _rideAgeMs > 15000) {
                const customerChatId = await getCustomerChatId(after);
                if (customerChatId) {
                    // 🔧 v6.36.0: Gastname hat Priorität über Hotel/CRM-Name
                    const _passengerName3 = after.guestName || after.customerName;
                    const _greeting3 = _passengerName3 ? `Hallo ${_passengerName3},\n\n` : '';
                    const trackingLink = `https://umwelt-taxi-insel-usedom.de/Taxi-App/track.html?ride=${rideId}`;
                    const vehicleInfo = after.vehicle ? `\n🚗 <b>Fahrzeug:</b> ${after.vehicle}${after.vehiclePlate ? ' (' + after.vehiclePlate + ')' : ''}` : '';
                    const customerMsg = `🚕 <b>IHRE FAHRT WURDE BESTELLT!</b> 🚕\n\n` +
                        _greeting3 +
                        `📍 <b>Von:</b> ${after.pickup || '?'}\n` +
                        `🎯 <b>Nach:</b> ${after.destination || '?'}\n` +
                        `🕐 <b>Abholung:</b> ${after.pickupTime || 'Sofort'}\n` +
                        (after.price ? `💰 <b>Preis:</b> ca. ${after.price}€` : '') +
                        vehicleInfo +
                        `\n\n📲 <b>Fahrt live verfolgen:</b>\n<a href="${trackingLink}">🗺️ Tracking öffnen</a>\n\n` +
                        `✅ Sie erhalten Updates sobald der Fahrer losfährt!\n\n` +
                        `📞 Bei Fragen: 038378/22022`;
                    await sendTelegramMessage(customerChatId, customerMsg);

                    // Flag setzen
                    try {
                        await db.ref('rides/' + rideId + '/customerTelegramSent').set(true);
                    } catch (e) { /* non-critical */ }
                }

                // 🆕 v6.28.0: WhatsApp-Benachrichtigung bei Fahrer-Zuweisung
                if (!after.customerWhatsAppSent) {
                    const waResult = await sendCustomerWhatsAppNotification(after, rideId, 'driver_assigned');
                    if (waResult) {
                        try { await db.ref('rides/' + rideId + '/customerWhatsAppSent').set(true); } catch (e) { /* */ }
                    }
                }
            }
        }

        // ═══════════════════════════════════════════════════════════════
        // 🔧 v6.38.53: vehicleScores für betroffene Fahrten neu berechnen
        // Wenn sich Zeit, Fahrzeug, Dauer oder Status ändert, stimmen die
        // Scores anderer Fahrten am selben Tag nicht mehr!
        // ═══════════════════════════════════════════════════════════════
        try {
            const _scoreRelevantChange =
                before.pickupTimestamp !== after.pickupTimestamp ||
                before.duration !== after.duration ||
                before.estimatedDuration !== after.estimatedDuration ||
                (before.assignedVehicle || before.vehicleId) !== (after.assignedVehicle || after.vehicleId) ||
                (before.status !== after.status && ['deleted','cancelled','storniert','completed','cancelled_pending_driver'].includes(after.status));

            if (_scoreRelevantChange && after.pickupTimestamp) {
                const _affectedVehicles = new Set();
                if (oldVehicle) _affectedVehicles.add(oldVehicle);
                if (newVehicle) _affectedVehicles.add(newVehicle);

                if (_affectedVehicles.size > 0) {
                    // Alle Fahrten am selben Tag laden
                    const _pickupBerlin = new Date(new Date(after.pickupTimestamp).toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
                    const _dayStart = new Date(_pickupBerlin);
                    _dayStart.setHours(0, 0, 0, 0);
                    const _dayEnd = new Date(_pickupBerlin);
                    _dayEnd.setHours(23, 59, 59, 999);

                    const _allRidesSnap = await db.ref('rides')
                        .orderByChild('pickupTimestamp')
                        .startAt(_dayStart.getTime())
                        .endAt(_dayEnd.getTime())
                        .once('value');
                    const _allRidesData = _allRidesSnap.val() || {};

                    const _dayRides = Object.entries(_allRidesData)
                        .filter(([id, r]) => r && r.pickupTimestamp && !['deleted','cancelled','storniert','cancelled_pending_driver'].includes(r.status))
                        .map(([id, r]) => ({ ...r, firebaseId: id }));

                    const boardingTime = 2, alightingTime = 2;
                    const _bufMs = (boardingTime + alightingTime) * 60000;
                    const _returnBufferMs = 5 * 60000;

                    // Für jede betroffene Fahrt die vehicleScores aktualisieren
                    let _updatedCount = 0;
                    for (const [otherRideId, otherRide] of Object.entries(_allRidesData)) {
                        if (otherRideId === rideId) continue; // Eigene Fahrt überspringen
                        if (!otherRide || !otherRide.pickupTimestamp) continue;
                        if (['deleted','cancelled','storniert','cancelled_pending_driver'].includes(otherRide.status)) continue;
                        if (!otherRide.vehicleScores) continue; // Nur Fahrten mit vorhandenen Scores

                        let _needsUpdate = false;
                        const _scores = { ...otherRide.vehicleScores };

                        for (const vid of _affectedVehicles) {
                            if (!_scores[vid]) continue; // Fahrzeug nicht in den Scores

                            // Neu berechnen: Ist dieses Fahrzeug für die andere Fahrt besetzt?
                            const _otherPickup = otherRide.pickupTimestamp;
                            let _isBusy = false;
                            let _latestEndMs = 0;
                            let _blockingRideName = '';
                            let _blockingRideDest = '';
                            let _blockingRideTime = '';

                            for (const dr of _dayRides) {
                                if (dr.firebaseId === otherRideId) continue;
                                if ((dr.vehicleId || dr.assignedVehicle) !== vid && (dr.assignedVehicle || dr.vehicleId) !== vid) continue;
                                const _drDur = (dr.duration || dr.estimatedDuration || 20) * 60000;
                                const _drEnd = dr.pickupTimestamp + _drDur + _bufMs + _returnBufferMs;
                                const _drApproach = dr.pickupTimestamp - 10 * 60000;

                                // Überlappung: Fahrt davor endet nach unserem Pickup ODER Fahrt danach startet bald
                                if ((dr.pickupTimestamp <= _otherPickup && _drEnd > _otherPickup) ||
                                    (dr.pickupTimestamp > _otherPickup && _drApproach <= _otherPickup)) {
                                    _isBusy = true;
                                    if (_drEnd > _latestEndMs) {
                                        _latestEndMs = _drEnd;
                                        _blockingRideName = dr.customerName || '';
                                        _blockingRideDest = dr.destination || '';
                                        _blockingRideTime = new Date(dr.pickupTimestamp).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                                    }
                                }
                            }

                            const _oldStatus = _scores[vid].status;
                            if (_isBusy && _oldStatus !== 'busy' && _oldStatus !== 'overlap-hard') {
                                // Fahrzeug ist jetzt besetzt, war vorher frei
                                const _busyUntilStr = new Date(_latestEndMs).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                                _scores[vid] = { ..._scores[vid], status: 'busy', busyUntil: _busyUntilStr, blockingRideCustomer: _blockingRideName, blockingRideDest: _blockingRideDest, blockingRideTime: _blockingRideTime };
                                _needsUpdate = true;
                            } else if (!_isBusy && (_oldStatus === 'busy' || _oldStatus === 'overlap-hard')) {
                                // Fahrzeug ist jetzt frei, war vorher besetzt (z.B. Fahrt storniert)
                                _scores[vid] = { ..._scores[vid], status: 'available', busyUntil: null, blockingRideCustomer: null, blockingRideDest: null, overlapMin: null };
                                _needsUpdate = true;
                            } else if (_isBusy && _latestEndMs > 0) {
                                // War schon besetzt — busyUntil aktualisieren
                                const _busyUntilStr = new Date(_latestEndMs).toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Berlin' });
                                if (_scores[vid].busyUntil !== _busyUntilStr) {
                                    _scores[vid] = { ..._scores[vid], busyUntil: _busyUntilStr, blockingRideCustomer: _blockingRideName, blockingRideDest: _blockingRideDest, blockingRideTime: _blockingRideTime };
                                    _needsUpdate = true;
                                }
                            }
                        }

                        if (_needsUpdate) {
                            await db.ref('rides/' + otherRideId + '/vehicleScores').set(_scores);
                            _updatedCount++;
                        }
                    }

                    if (_updatedCount > 0) {
                        console.log(`🔄 v6.38.53: vehicleScores für ${_updatedCount} betroffene Fahrt(en) aktualisiert`);
                    }
                }
            }
        } catch (e) {
            console.error('⚠️ vehicleScores-Refresh Fehler:', e.message);
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// TRIGGER 3: Fahrt gelöscht → Admin-Benachrichtigung
// ═══════════════════════════════════════════════════════════════
exports.onRideDeleted = onValueDeleted(
    {
        ref: '/rides/{rideId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const rideId = event.params.rideId;
        const ride = event.data.val();
        if (!ride) return;

        console.log(`📱 onRideDeleted: ${rideId} — ${ride.customerName || 'Unbekannt'}`);

        const timestamp = formatBerlinTime();

        let statusText = 'Nicht zugewiesen';
        if (ride.status === 'accepted') statusText = '✅ Angenommen';
        if (ride.status === 'picked_up') statusText = '🚗 Unterwegs';
        if (ride.status === 'vorbestellt') statusText = '📅 Vorbestellt';

        const message = `🗑️ <b>FAHRT GELÖSCHT</b>\n` +
            `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
            `⚠️ <b>Status war:</b> ${statusText}\n` +
            (ride.vehicle ? `🚗 <b>Fahrzeug:</b> ${ride.vehicle}${ride.vehiclePlate ? ` (${ride.vehiclePlate})` : ''}\n` : '') +
            `👤 <b>Kunde:</b> ${ride.customerName || '?'}\n` +
            `📱 <b>Tel:</b> ${ride.customerPhone || '?'}${formatWhatsAppLink(ride.customerPhone || ride.customerMobile)}\n` +
            `📍 <b>Von:</b> ${ride.pickup || '?'}\n` +
            `📍 <b>Nach:</b> ${ride.destination || '?'}\n` +
            (ride.pickupTime && ride.pickupTime !== 'Sofort' ? `⏰ <b>Abholung:</b> ${ride.pickupTime}\n` : '') +
            `💰 <b>Preis:</b> ${ride.price || 0}€\n` +
            `⏰ <b>Gelöscht:</b> ${timestamp}\n` +
            `\n🚨 <b>Diese Fahrt wurde gelöscht!</b>`;

        await sendToAllAdmins(message, 'ride_deleted');
        await sendToSystemChannel(message, 'ride_deleted');

        // Fahrer benachrichtigen falls zugewiesen
        const vehicleId = ride.assignedVehicle || ride.vehicleId;
        if (vehicleId) {
            const driverChatId = await getDriverChatId(vehicleId);
            if (driverChatId) {
                await sendTelegramMessage(driverChatId,
                    `🗑️ <b>FAHRT GELÖSCHT!</b>\n\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n` +
                    `👤 <b>Kunde:</b> ${ride.customerName || '?'}\n` +
                    `📍 <b>Von:</b> ${ride.pickup || '?'}\n\n` +
                    `⚠️ Diese Fahrt wurde vom Admin gelöscht.`
                );
            }
        }

        await addTelegramLog('🗑️', 'cloud', `Fahrt gelöscht: ${ride.customerName || '?'}`, { rideId });
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.20.0: OFFENE FAHRTEN PRÜFUNG (alle 1 Minute)
// Warnt Admins wenn Vorbestellungen < 10 Min vor Abholzeit ohne Fahrer sind
// ═══════════════════════════════════════════════════════════════
exports.scheduledOpenRideCheck = onSchedule(
    {
        schedule: 'every 1 minutes',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const ridesSnap = await db.ref('rides').once('value');
            if (!ridesSnap.val()) return;

            const now = Date.now();
            const warnings = [];

            ridesSnap.forEach(child => {
                const ride = child.val();
                const rideId = child.key;

                // Nur Fahrten ohne Fahrer prüfen
                if (ride.status !== 'new' && ride.status !== 'vorbestellt') return;
                if (ride.assignedVehicle || ride.vehicleId || ride.driverId) return;

                // Prüfe ob Abholzeit in <= 10 Minuten
                const pickupTime = ride.pickupTimestamp || 0;
                const minutesUntilPickup = (pickupTime - now) / (1000 * 60);

                if (minutesUntilPickup <= 10 && minutesUntilPickup > -5) {
                    // Prüfe ob schon gewarnt (Flag in Firebase)
                    if (!ride.openRideWarned) {
                        warnings.push({ rideId, ride, minutesUntilPickup });
                    }
                }
            });

            // 🆕 v6.38.97: Timeout für 'sofort' Fahrten — Fahrer hat nicht bestätigt
            ridesSnap.forEach(child => {
                const ride = child.val();
                const rideId = child.key;
                if (ride.status !== 'sofort') return;
                if (!ride.assignmentExpiresAt) return;
                if (ride.assignmentExpiresAt > now) return; // Noch nicht abgelaufen

                // Abgelaufen! Fahrzeug entfernen und neu zuweisen
                const expiredVehicle = ride.assignedVehicle || ride.vehicleId;
                const expiredName = ride.vehicle || ride.assignedVehicleName || expiredVehicle;
                console.log(`⏰ Sofortfahrt ${rideId} abgelaufen — ${expiredName} hat nicht bestätigt`);

                // Bisherige abgelehnte Fahrzeuge merken
                const rejectedVehicles = ride.rejectedVehicles || [];
                if (expiredVehicle) rejectedVehicles.push(expiredVehicle);

                // Fahrzeug entfernen, Status zurück auf 'new'
                db.ref('rides/' + rideId).update({
                    status: 'new',
                    assignedVehicle: null,
                    vehicleId: null,
                    vehicle: null,
                    assignedTo: null,
                    assignedAt: null,
                    assignedBy: null,
                    assignmentExpiresAt: null,
                    rejectedVehicles: rejectedVehicles,
                    updatedAt: Date.now()
                }).then(() => {
                    // Neu zuweisen (ohne abgelehnte Fahrzeuge)
                    console.log(`🔄 Versuche Neuzuweisung für ${rideId} (ohne ${rejectedVehicles.join(', ')})`);
                    autoAssignRide(rideId, { ...ride, _rejectedVehicles: rejectedVehicles }).then(result => {
                        if (result) {
                            console.log(`✅ Neu zugewiesen: ${rideId} → ${result.name}`);
                        } else {
                            console.log(`⚠️ Kein Fahrzeug mehr verfügbar für ${rideId}`);
                            sendToAllAdmins(`⚠️ <b>Sofortfahrt ohne Fahrer!</b>\n\n${ride.customerName || '?'}\n📍 ${ride.pickup}\n🎯 ${ride.destination}\n\nKein Fahrer hat bestätigt!`, 'unassigned');
                        }
                    });
                }).catch(e => console.error('Timeout-Reset Fehler:', e.message));
            });

            if (warnings.length === 0) return;

            const timestamp = formatBerlinTime();

            for (const { rideId, ride, minutesUntilPickup } of warnings) {
                const pickupTimeStr = ride.pickupTime || 'Unbekannt';
                const message = `🚨🚨🚨 <b>ACHTUNG: OFFENE FAHRT!</b> 🚨🚨🚨\n` +
                    `🆔 <b>ID:</b> <code>${rideId}</code>\n\n` +
                    `⏰ <b>Abholzeit:</b> ${pickupTimeStr}\n` +
                    `⚠️ <b>Noch KEIN Fahrer zugewiesen!</b>\n` +
                    `⏳ <b>Noch ${Math.max(0, Math.round(minutesUntilPickup))} Minuten!</b>\n\n` +
                    `👤 <b>Kunde:</b> ${ride.customerName || '?'}\n` +
                    `📱 <b>Tel:</b> ${ride.customerPhone || '?'}${formatWhatsAppLink(ride.customerPhone || ride.customerMobile)}\n` +
                    `📍 <b>Von:</b> ${ride.pickup || '?'}\n` +
                    `📍 <b>Nach:</b> ${ride.destination || '?'}\n` +
                    `💰 <b>Preis:</b> ${ride.price || 0}€\n\n` +
                    `🔴 <b>Bitte SOFORT einen Fahrer zuweisen!</b>\n` +
                    `⏰ <b>Warnung:</b> ${timestamp}`;

                await sendToAllAdmins(message, 'unassigned');
                await sendToSystemChannel(message, 'unassigned');

                // Flag setzen damit nicht nochmal gewarnt wird
                try {
                    await db.ref('rides/' + rideId + '/openRideWarned').set(true);
                } catch (e) { /* non-critical */ }

                await addTelegramLog('🚨', 'cloud', `OFFENE FAHRT Warnung: ${ride.customerName || '?'} (${pickupTimeStr})`, { rideId });
                console.log(`🚨 Offene-Fahrt-Warnung gesendet: ${rideId}`);
            }
        } catch (e) {
            console.error('❌ scheduledOpenRideCheck Fehler:', e.message);
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 💳 STRIPE CHECKOUT — v6.21.0
// Erstellt eine Stripe Checkout Session für eine Rechnung
// ═══════════════════════════════════════════════════════════════

exports.createStripeCheckout = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        // CORS
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const { invoiceNumber, amount, customerName, customerEmail, description } = req.body;

            if (!invoiceNumber || !amount) {
                res.status(400).json({ error: 'invoiceNumber und amount sind erforderlich' });
                return;
            }

            const stripe = await getStripe();

            // Betrag in Cent (Stripe erwartet kleinste Währungseinheit)
            const amountInCents = Math.round(parseFloat(amount) * 100);

            if (amountInCents < 50) {
                res.status(400).json({ error: 'Mindestbetrag ist 0,50 €' });
                return;
            }

            // Checkout Session erstellen
            // payment_method_types NICHT setzen → Stripe nutzt automatisch alle im Dashboard aktivierten Methoden
            const sessionParams = {
                mode: 'payment',
                line_items: [{
                    price_data: {
                        currency: 'eur',
                        product_data: {
                            name: `Rechnung ${invoiceNumber}`,
                            description: description || `Funk Taxi Heringsdorf — Rechnung ${invoiceNumber}`
                        },
                        unit_amount: amountInCents
                    },
                    quantity: 1
                }],
                metadata: {
                    invoiceNumber: invoiceNumber,
                    source: 'taxi-heringsdorf'
                },
                success_url: `https://taxi-heringsdorf.web.app/payment-success?invoice=${invoiceNumber}`,
                cancel_url: `https://taxi-heringsdorf.web.app/payment-cancel?invoice=${invoiceNumber}`,
                locale: 'de'
            };

            // Optional: Kunden-E-Mail vorausfüllen
            if (customerEmail) {
                sessionParams.customer_email = customerEmail;
            }

            const session = await stripe.checkout.sessions.create(sessionParams);

            // Speichere Checkout-Info in Firebase
            await db.ref(`invoices/${invoiceNumber}`).update({
                stripeSessionId: session.id,
                stripeCheckoutUrl: session.url,
                stripePaymentStatus: 'pending',
                stripeCreatedAt: Date.now()
            });

            console.log(`💳 Stripe Checkout erstellt: ${invoiceNumber} → ${session.id}`);

            res.status(200).json({
                success: true,
                checkoutUrl: session.url,
                sessionId: session.id
            });

        } catch (error) {
            console.error('❌ Stripe Checkout Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 💳 STRIPE BEZAHL-REDIRECT — v6.22.0
// Kurze URL für QR-Codes: /pay?inv=INV-2026-00123
// Leitet weiter zur Stripe Checkout URL
// ═══════════════════════════════════════════════════════════════

exports.payRedirect = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        const invoiceNumber = req.query.inv || req.params[0];

        if (!invoiceNumber) {
            res.status(400).send('Fehlende Rechnungsnummer');
            return;
        }

        try {
            const snap = await db.ref(`invoices/${invoiceNumber}`).once('value');
            const invoice = snap.val();

            if (!invoice || !invoice.stripeCheckoutUrl) {
                res.status(404).send('Bezahl-Link nicht gefunden oder abgelaufen');
                return;
            }

            // Wenn bereits bezahlt → Bestätigungsseite
            if (invoice.stripePaymentStatus === 'paid') {
                res.status(200).send(`<html><body style="font-family:sans-serif;text-align:center;padding:40px;">
                    <h2>✅ Bereits bezahlt</h2>
                    <p>Rechnung ${invoiceNumber} wurde bereits beglichen.</p>
                    <p>Betrag: ${invoice.totalGross ? invoice.totalGross.toFixed(2) : '?'} €</p>
                </body></html>`);
                return;
            }

            console.log(`💳 Pay-Redirect: ${invoiceNumber} → Stripe Checkout`);
            res.redirect(302, invoice.stripeCheckoutUrl);

        } catch (error) {
            console.error('❌ Pay-Redirect Fehler:', error.message);
            res.status(500).send('Fehler beim Laden des Bezahl-Links');
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 💳 STRIPE WEBHOOK — v6.21.0
// Empfängt Zahlungsbestätigungen von Stripe
// ═══════════════════════════════════════════════════════════════

exports.stripeWebhook = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        if (req.method !== 'POST') {
            res.status(405).send('Method not allowed');
            return;
        }

        try {
            const stripe = await getStripe();

            // Webhook-Signatur verifizieren (optional, empfohlen für Produktion)
            let event;
            const webhookSecret = await db.ref('settings/stripe/webhookSecret').once('value').then(s => s.val());

            if (webhookSecret) {
                const sig = req.headers['stripe-signature'];
                try {
                    event = stripe.webhooks.constructEvent(req.rawBody, sig, webhookSecret);
                } catch (err) {
                    console.error('⚠️ Stripe Webhook Signatur ungültig:', err.message);
                    res.status(400).send(`Webhook Error: ${err.message}`);
                    return;
                }
            } else {
                // Ohne Secret: Event direkt verwenden (nur für Tests!)
                event = req.body;
                console.warn('⚠️ Stripe Webhook ohne Signatur-Verifizierung!');
            }

            // Verarbeite Event
            if (event.type === 'checkout.session.completed') {
                const session = event.data.object;
                const invoiceNumber = session.metadata?.invoiceNumber;

                if (invoiceNumber) {
                    // Rechnung als bezahlt markieren
                    await db.ref(`invoices/${invoiceNumber}`).update({
                        stripePaymentStatus: 'paid',
                        stripePaidAt: Date.now(),
                        stripePaymentIntentId: session.payment_intent,
                        stripeAmountPaid: session.amount_total,
                        status: 'bezahlt',
                        paidAt: Date.now(),
                        paymentMethod: 'stripe'
                    });

                    console.log(`✅ Stripe Zahlung erhalten: ${invoiceNumber} → ${(session.amount_total / 100).toFixed(2)} €`);

                    // Optional: Admin benachrichtigen via Telegram
                    try {
                        const invoiceSnap = await db.ref(`invoices/${invoiceNumber}`).once('value');
                        const invoice = invoiceSnap.val();
                        const amountEur = (session.amount_total / 100).toFixed(2);

                        const adminMsg = `💳✅ <b>Zahlung eingegangen!</b>\n\n` +
                            `📄 <b>Rechnung:</b> ${invoiceNumber}\n` +
                            `👤 <b>Kunde:</b> ${invoice?.customerName || session.customer_details?.name || '?'}\n` +
                            `💰 <b>Betrag:</b> ${amountEur} €\n` +
                            `💳 <b>Zahlungsart:</b> Stripe Checkout\n` +
                            `⏰ <b>Zeit:</b> ${formatBerlinTime()}`;

                        await sendToAllAdmins(adminMsg, 'payment');
                        await sendToSystemChannel(adminMsg, 'payment');
                    } catch (notifyErr) {
                        console.warn('⚠️ Admin-Benachrichtigung fehlgeschlagen:', notifyErr.message);
                    }
                }
            } else if (event.type === 'checkout.session.expired') {
                const session = event.data.object;
                const invoiceNumber = session.metadata?.invoiceNumber;
                if (invoiceNumber) {
                    await db.ref(`invoices/${invoiceNumber}`).update({
                        stripePaymentStatus: 'expired',
                        stripeExpiredAt: Date.now()
                    });
                    console.log(`⏰ Stripe Session abgelaufen: ${invoiceNumber}`);
                }
            }

            res.status(200).json({ received: true });

        } catch (error) {
            console.error('❌ Stripe Webhook Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 📧 EMAIL-VERSAND — v6.21.0
// Versendet Rechnungen per SMTP (Nodemailer) statt EmailJS
// ═══════════════════════════════════════════════════════════════

exports.sendInvoiceEmail = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        // CORS
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const {
                invoiceNumber,
                toEmail,
                toName,
                subject,
                htmlBody,
                paymentLink,  // Optional: Stripe Checkout URL
                pdfUrl,       // Optional: PDF-URL für Anhang
                attachPdf     // Optional: true = PDF als Anhang senden
            } = req.body;

            if (!toEmail || !invoiceNumber) {
                res.status(400).json({ error: 'toEmail und invoiceNumber sind erforderlich' });
                return;
            }

            // SMTP-Einstellungen aus Firebase laden
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();

            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert! Bitte unter Einstellungen → Rechnungseinstellungen → SMTP einrichten.' });
                return;
            }

            // Nodemailer Transporter erstellen
            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: {
                    user: smtp.user,
                    pass: smtp.pass
                }
            });

            // Rechnungsdaten aus Firebase laden (wenn kein htmlBody mitgegeben)
            let emailHTML = htmlBody;
            let emailSubject = subject;

            if (!emailHTML) {
                // Rechnung aus Firebase laden und HTML generieren
                const invoiceSnap = await db.ref(`invoices/${invoiceNumber}`).once('value');
                const invoice = invoiceSnap.val();

                if (!invoice) {
                    res.status(404).json({ error: `Rechnung ${invoiceNumber} nicht gefunden` });
                    return;
                }

                // Firmen-Einstellungen laden
                const settingsSnap = await db.ref('settings/invoice').once('value');
                const invSettings = settingsSnap.val() || {};
                const companyName = invSettings.companyName || 'Taxi Wydra';
                const companyPhone = invSettings.phone || '+49 151 27585179';
                const companyEmail = invSettings.email || 'taxiwydra@googlemail.com';
                const ownerName = invSettings.ownerName || 'Patrick Wydra';

                const customerName = toName || invoice.customerName || 'Kunde';
                const pdfUrl = invoice.pdfUrl || '';
                const totalGross = parseFloat(invoice.totalGross) || 0;
                const totalNet = parseFloat(invoice.totalNet) || 0;

                // Positionen-HTML
                const positions = invoice.positions || [];
                const positionsHTML = positions.map(pos => `
                    <tr>
                        <td style="padding:8px;border:1px solid #e5e7eb;">${pos.description || 'Position'}</td>
                        <td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(pos.amount).toFixed(2)} &euro;</td>
                    </tr>
                `).join('');

                // MwSt-Aufschlüsselung
                const vatBreakdown = invoice.vatBreakdown || {};
                const netBreakdown = invoice.netBreakdown || {};
                const vatRates = Object.keys(vatBreakdown).sort((a, b) => parseFloat(b) - parseFloat(a));

                let vatHTML = '';
                if (vatRates.length === 1) {
                    const rate = vatRates[0];
                    vatHTML = `<tr><td style="padding:8px;border:1px solid #e5e7eb;">zzgl. MwSt (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(vatBreakdown[rate]).toFixed(2)} &euro;</td></tr>`;
                } else {
                    vatHTML = vatRates.map(rate => `
                        <tr><td style="padding:8px;border:1px solid #e5e7eb;">davon Netto (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(netBreakdown[rate]).toFixed(2)} &euro;</td></tr>
                        <tr><td style="padding:8px;border:1px solid #e5e7eb;">davon MwSt (${parseFloat(rate).toFixed(0)}%):</td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${parseFloat(vatBreakdown[rate]).toFixed(2)} &euro;</td></tr>
                    `).join('');
                }

                // Bezahl-Link-Bereich (wenn Stripe aktiv)
                const stripeUrl = paymentLink || invoice.stripeCheckoutUrl || '';
                const paymentSection = stripeUrl ? `
                    <div style="background:#f0f0ff;border:2px solid #635bff;border-radius:8px;padding:15px;margin:20px 0;text-align:center;">
                        <p style="margin:0 0 10px 0;font-weight:700;color:#0a2540;">&#x1F4B3; Jetzt online bezahlen</p>
                        <a href="${stripeUrl}" style="display:inline-block;background:#635bff;color:white;padding:12px 30px;text-decoration:none;border-radius:6px;font-weight:bold;">Zur sicheren Zahlung</a>
                        <p style="font-size:12px;color:#6b7280;margin:10px 0 0 0;">Kreditkarte, Giropay oder Sofort&uuml;berweisung</p>
                    </div>
                ` : '';

                // PDF-Download-Bereich
                const pdfSection = pdfUrl ? `
                    <div style="background:#dbeafe;border-left:4px solid #3b82f6;padding:15px;margin:20px 0;">
                        <h3 style="margin-top:0;">&#x1F4C4; Ihre Rechnung als PDF</h3>
                        <p><a href="${pdfUrl}" style="display:inline-block;background:#3b82f6;color:white;padding:12px 24px;text-decoration:none;border-radius:6px;font-weight:bold;">&#x1F4E5; Rechnung herunterladen</a></p>
                    </div>
                ` : '';

                emailHTML = `
                    <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;color:#1f2937;">
                        <div style="background:linear-gradient(135deg,#3b82f6,#1d4ed8);color:white;padding:20px;border-radius:8px 8px 0 0;text-align:center;">
                            <h2 style="margin:0;">Rechnung ${invoiceNumber}</h2>
                            <p style="margin:5px 0 0 0;opacity:0.9;">${companyName}</p>
                        </div>
                        <div style="padding:20px;background:#ffffff;border:1px solid #e5e7eb;">
                            <p>Guten Tag ${customerName},</p>
                            <p>vielen Dank f&uuml;r Ihre Fahrt mit ${companyName}!</p>

                            <h3>&#x1F4CB; Rechnungsdetails:</h3>
                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Rechnungsnummer:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoiceNumber}</td></tr>
                                <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Datum:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.rideDate || ''} ${invoice.rideTime || ''}</td></tr>
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Von:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.pickup || ''}</td></tr>
                                <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Nach:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${invoice.destination || ''}</td></tr>
                            </table>

                            <h3>&#x1F4CA; Positionen:</h3>
                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#3b82f6;color:white;"><th style="padding:8px;text-align:left;">Beschreibung</th><th style="padding:8px;text-align:right;">Betrag</th></tr>
                                ${positionsHTML}
                            </table>

                            <table style="border-collapse:collapse;width:100%;margin:15px 0;">
                                <tr style="background:#f3f4f6;"><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Netto:</strong></td><td style="padding:8px;border:1px solid #e5e7eb;text-align:right;">${totalNet.toFixed(2)} &euro;</td></tr>
                                ${vatHTML}
                                <tr style="background:#10b981;color:white;"><td style="padding:8px;border:1px solid #059669;"><strong>Gesamt (brutto):</strong></td><td style="padding:8px;border:1px solid #059669;text-align:right;"><strong>${totalGross.toFixed(2)} &euro;</strong></td></tr>
                            </table>

                            ${paymentSection}
                            ${pdfSection}

                            <p>Bei Fragen stehen wir Ihnen gerne zur Verf&uuml;gung.</p>
                            <p>Mit freundlichen Gr&uuml;&szlig;en<br>${ownerName}<br><strong>${companyName}</strong></p>
                        </div>
                        <div style="background:#f9fafb;padding:15px;border-radius:0 0 8px 8px;text-align:center;font-size:12px;color:#6b7280;border:1px solid #e5e7eb;border-top:none;">
                            &#x1F4DE; ${companyPhone} &nbsp;|&nbsp; &#x2709; ${companyEmail}
                        </div>
                    </div>
                `;

                emailSubject = subject || `Ihre Rechnung ${invoiceNumber} - ${companyName}`;
            }

            // Absender-Name aus Settings
            const fromName = smtp.fromName || 'Taxi Wydra';
            const fromEmail = smtp.fromEmail || smtp.user;

            // 🆕 v6.22.0: PDF als Anhang herunterladen (wenn gewünscht)
            let attachments = [];
            const shouldAttachPdf = attachPdf !== false; // Standard: immer anhängen wenn pdfUrl vorhanden
            const effectivePdfUrl = pdfUrl || (emailHTML ? null : (invoice ? invoice.pdfUrl : null));

            if (shouldAttachPdf && effectivePdfUrl) {
                try {
                    console.log('📎 Lade PDF für Anhang:', effectivePdfUrl);
                    const https = require('https');
                    const http = require('http');
                    const pdfBuffer = await new Promise((resolve, reject) => {
                        const client = effectivePdfUrl.startsWith('https') ? https : http;
                        client.get(effectivePdfUrl, (response) => {
                            // Redirects folgen
                            if (response.statusCode === 301 || response.statusCode === 302) {
                                client.get(response.headers.location, (res2) => {
                                    const chunks = [];
                                    res2.on('data', chunk => chunks.push(chunk));
                                    res2.on('end', () => resolve(Buffer.concat(chunks)));
                                    res2.on('error', reject);
                                }).on('error', reject);
                                return;
                            }
                            const chunks = [];
                            response.on('data', chunk => chunks.push(chunk));
                            response.on('end', () => resolve(Buffer.concat(chunks)));
                            response.on('error', reject);
                        }).on('error', reject);
                    });

                    attachments.push({
                        filename: `rechnung-${invoiceNumber}.pdf`,
                        content: pdfBuffer,
                        contentType: 'application/pdf'
                    });
                    console.log(`📎 PDF-Anhang bereit: ${pdfBuffer.length} Bytes`);
                } catch (pdfError) {
                    console.warn('⚠️ PDF konnte nicht als Anhang geladen werden:', pdfError.message);
                    // Kein Abbruch — E-Mail wird trotzdem gesendet (mit Download-Link)
                }
            }

            // Email senden
            const mailOptions = {
                from: `"${fromName}" <${fromEmail}>`,
                to: toEmail,
                subject: emailSubject || `Rechnung ${invoiceNumber}`,
                html: emailHTML,
                attachments: attachments
            };

            const info = await transporter.sendMail(mailOptions);
            console.log(`📧 Email gesendet: ${invoiceNumber} → ${toEmail} (${info.messageId})`);

            // Status in Firebase aktualisieren
            const updateData = {
                emailSent: true,
                emailSentAt: Date.now(),
                emailSentTo: toEmail,
                emailSentVia: 'smtp',
                emailMessageId: info.messageId,
                status: 'versendet'
            };

            await db.ref(`invoices/${invoiceNumber}`).update(updateData);

            // Auch Ride aktualisieren wenn vorhanden
            const invoiceSnap2 = await db.ref(`invoices/${invoiceNumber}/rideId`).once('value');
            const rideId = invoiceSnap2.val();
            if (rideId) {
                await db.ref(`rides/${rideId}`).update({
                    invoiceSent: true,
                    invoiceSentAt: Date.now(),
                    invoiceSentVia: 'email',
                    invoiceSentTo: toEmail
                });
            }

            res.status(200).json({
                success: true,
                messageId: info.messageId,
                sentTo: toEmail
            });

        } catch (error) {
            console.error('❌ Email-Versand Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 📧 SMTP TEST — v6.21.0
// Testet SMTP-Verbindung mit Test-Email
// ═══════════════════════════════════════════════════════════════

exports.testSmtpConnection = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        try {
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();

            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert' });
                return;
            }

            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });

            // Verbindung testen
            await transporter.verify();

            // Test-Email an sich selbst senden
            const testTo = req.body?.testEmail || smtp.user;
            await transporter.sendMail({
                from: `"${smtp.fromName || 'Taxi Wydra'}" <${smtp.fromEmail || smtp.user}>`,
                to: testTo,
                subject: 'SMTP Test - Taxi App',
                html: '<div style="font-family:Arial;padding:20px;"><h2>&#x2705; SMTP funktioniert!</h2><p>Diese Test-Email wurde erfolgreich von deiner Taxi-App versendet.</p><p style="color:#6b7280;font-size:12px;">Gesendet am: ' + formatBerlinTime() + '</p></div>'
            });

            console.log(`📧 SMTP Test erfolgreich → ${testTo}`);
            res.status(200).json({ success: true, sentTo: testTo });

        } catch (error) {
            console.error('❌ SMTP Test Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

