// ═══════════════════════════════════════════════════════════════
// 🆕 v6.25.4: WhatsApp Business API — Rechnung als PDF-Anhang senden
// ═══════════════════════════════════════════════════════════════

exports.sendInvoiceWhatsApp = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const { invoiceNumber, phone, customerName, amount, pdfUrl } = req.body;

            if (!invoiceNumber || !phone || !pdfUrl) {
                res.status(400).json({ error: 'invoiceNumber, phone und pdfUrl sind erforderlich' });
                return;
            }

            // WhatsApp Business API Credentials aus Firebase laden
            const tokenSnap = await db.ref('settings/whatsapp/apiToken').once('value');
            const phoneIdSnap = await db.ref('settings/whatsapp/phoneNumberId').once('value');
            const apiToken = tokenSnap.val();
            const apiPhoneId = phoneIdSnap.val();

            if (!apiToken || !apiPhoneId) {
                res.status(400).json({ error: 'WhatsApp Business API nicht konfiguriert! Bitte apiToken und phoneNumberId unter settings/whatsapp eintragen.' });
                return;
            }

            // Telefonnummer formatieren (international ohne +)
            let formattedPhone = phone.replace(/[\s\-\/\(\)]/g, '');
            if (formattedPhone.startsWith('0')) {
                formattedPhone = '49' + formattedPhone.substring(1);
            } else if (formattedPhone.startsWith('+')) {
                formattedPhone = formattedPhone.substring(1);
            }

            const waApiUrl = `https://graph.facebook.com/v21.0/${apiPhoneId}/messages`;

            // Schritt 1: PDF als Dokument senden
            console.log(`📤 Sende PDF an ${formattedPhone}...`);
            const docResponse = await fetch(waApiUrl, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${apiToken}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    messaging_product: 'whatsapp',
                    to: formattedPhone,
                    type: 'document',
                    document: {
                        link: pdfUrl,
                        filename: `Rechnung-${invoiceNumber}.pdf`,
                        caption: `📄 Rechnung Nr. ${invoiceNumber} über ${parseFloat(amount || 0).toFixed(2)} €\n\nVielen Dank!\nTaxi Patrick Wydra\n📞 038378/22022`
                    }
                })
            });

            const docResult = await docResponse.json();

            if (!docResponse.ok) {
                console.error('❌ WhatsApp API Fehler:', JSON.stringify(docResult));
                res.status(docResponse.status).json({
                    error: 'WhatsApp API Fehler',
                    details: docResult
                });
                return;
            }

            console.log('✅ PDF per WhatsApp gesendet:', docResult.messages?.[0]?.id);

            // In Firebase loggen
            await db.ref(`invoices/${invoiceNumber}`).update({
                whatsappSentAt: Date.now(),
                whatsappSentTo: formattedPhone,
                whatsappMessageId: docResult.messages?.[0]?.id || null,
                invoiceSentVia: 'whatsapp_api'
            });

            // Protokoll
            await db.ref('emailLog').push({
                type: 'whatsapp_invoice',
                invoiceNumber,
                to: formattedPhone,
                customerName: customerName || '',
                amount: amount || 0,
                messageId: docResult.messages?.[0]?.id || null,
                status: 'sent',
                sentAt: Date.now()
            });

            res.status(200).json({
                success: true,
                messageId: docResult.messages?.[0]?.id,
                to: formattedPhone
            });

        } catch (error) {
            console.error('❌ WhatsApp Rechnung Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// CRM E-Mails
// ═══════════════════════════════════════════════════════════════

exports.sendCrmEmail = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        // CORS
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const {
                to,
                toName,
                subject,
                htmlBody,
                replyTo,    // Optional: Antwort-Adresse (z.B. Kunden-Email bei Anfragen)
                attachment  // Optional: { filename, content (base64), contentType }
            } = req.body;

            if (!to || !subject) {
                res.status(400).json({ error: 'to und subject sind erforderlich' });
                return;
            }

            // SMTP-Einstellungen aus Firebase laden
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();

            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert! Bitte unter CRM → Einstellungen → SMTP einrichten.' });
                return;
            }

            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });

            // E-Mail-Optionen
            const mailOptions = {
                from: `"${smtp.fromName || 'Taxi Wydra'}" <${smtp.fromEmail || smtp.user}>`,
                to: toName ? `"${toName}" <${to}>` : to,
                subject: subject,
                html: htmlBody || `<p>${subject}</p>`,
                ...(replyTo && { replyTo: replyTo })
            };

            // Anhang hinzufügen wenn vorhanden
            if (attachment && attachment.content && attachment.filename) {
                mailOptions.attachments = [{
                    filename: attachment.filename,
                    content: Buffer.from(attachment.content, 'base64'),
                    contentType: attachment.contentType || 'application/octet-stream'
                }];
            }

            const info = await transporter.sendMail(mailOptions);
            console.log(`📧 CRM E-Mail gesendet → ${to} (${subject})`, info.messageId);

            // In emailLog speichern
            await db.ref('emailLog').push({
                type: 'crm-manual',
                to: to,
                subject: subject,
                sentAt: Date.now(),
                messageId: info.messageId,
                hasAttachment: !!(attachment && attachment.filename),
                attachmentName: attachment?.filename || null
            });

            res.status(200).json({ success: true, messageId: info.messageId });

        } catch (error) {
            console.error('❌ CRM E-Mail Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.43: TÄGLICHE SYSTEMKONTROLLE
// Prüft jeden Morgen um 06:00 auf Unstimmigkeiten im System
// ═══════════════════════════════════════════════════════════════

exports.dailySystemCheck = onSchedule(
    {
        schedule: 'every day 06:00',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '256MiB'
    },
    async (event) => {
        console.log('🔍 Tägliche Systemkontrolle gestartet...');
        const now = Date.now();
        const today = new Date(now);
        const todayStr = today.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: '2-digit' });
        const issues = [];
        const stats = { rides: 0, vehicles: 0, customers: 0, pendings: 0 };

        try {
            // ═══════════════════════════════════════
            // 1. FAHRTEN-KONSISTENZ
            // ═══════════════════════════════════════
            const ridesSnap = await db.ref('rides').once('value');
            const rides = ridesSnap.val() || {};
            stats.rides = Object.keys(rides).length;

            let zombieRides = 0;         // Fahrten ohne Status
            let orphanedRides = 0;       // Fahrten mit gelöschtem Fahrzeug
            let pastOpenRides = 0;       // Offene Fahrten in der Vergangenheit
            let duplicateVehicle = {};   // Fahrzeug doppelt zugewiesen zur gleichen Zeit
            let missingCoords = 0;       // Fahrten ohne Koordinaten
            let missingPrice = 0;        // Fahrten ohne Preis
            let stuckPending = 0;        // Fahrten mit Status "new" > 2h alt

            for (const [rideId, ride] of Object.entries(rides)) {
                // Zombie-Rides (kein Status)
                if (!ride.status) {
                    zombieRides++;
                    issues.push(`🧟 Fahrt ${rideId} ohne Status (${ride.customerName || '?'})`);
                }

                // Vergangene offene Fahrten (> 2h in der Vergangenheit, noch "new" oder "vorbestellt")
                if (['new', 'vorbestellt', 'warteschlange'].includes(ride.status)) {
                    const pickupTs = ride.pickupTimestamp || ride.createdAt || 0;
                    if (pickupTs > 0 && pickupTs < now - 2 * 3600000) {
                        pastOpenRides++;
                        const age = Math.round((now - pickupTs) / 3600000);
                        issues.push(`⏰ Fahrt ${rideId} "${ride.status}" — ${age}h überfällig (${ride.customerName || '?'}: ${ride.pickup || '?'} → ${ride.destination || '?'})`);
                    }
                }

                // Steckengebliebene "new" Fahrten (> 2h, kein Fahrzeug)
                if (ride.status === 'new' && !ride.assignedVehicle && ride.createdAt && ride.createdAt < now - 2 * 3600000) {
                    stuckPending++;
                }

                // Aktive Fahrten ohne Koordinaten
                if (!['completed', 'cancelled', 'deleted', 'rejected'].includes(ride.status)) {
                    if (!ride.pickupLat || !ride.destinationLat) {
                        missingCoords++;
                    }
                    if (!ride.price && !ride.estimatedPrice) {
                        missingPrice++;
                    }
                }

                // Fahrzeug-Doppelbelegung prüfen (nur aktive Fahrten)
                if (ride.assignedVehicle && !['completed', 'cancelled', 'deleted', 'rejected'].includes(ride.status)) {
                    const vKey = ride.assignedVehicle;
                    if (!duplicateVehicle[vKey]) duplicateVehicle[vKey] = [];
                    duplicateVehicle[vKey].push({
                        rideId,
                        pickupTs: ride.pickupTimestamp || ride.createdAt,
                        duration: ride.duration || ride.estimatedDuration || 30,
                        customer: ride.customerName || '?'
                    });
                }
            }

            // Zeitkonflikte finden
            for (const [vehicleId, vehicleRides] of Object.entries(duplicateVehicle)) {
                if (vehicleRides.length < 2) continue;
                vehicleRides.sort((a, b) => (a.pickupTs || 0) - (b.pickupTs || 0));
                for (let i = 0; i < vehicleRides.length - 1; i++) {
                    const current = vehicleRides[i];
                    const next = vehicleRides[i + 1];
                    const currentEnd = (current.pickupTs || 0) + (current.duration || 30) * 60000;
                    if (next.pickupTs && next.pickupTs < currentEnd) {
                        const vName = (OFFICIAL_VEHICLES[vehicleId] || {}).name || vehicleId;
                        issues.push(`⚡ ZEITKONFLIKT: ${vName} — ${current.customer} (${current.rideId}) und ${next.customer} (${next.rideId}) überlappen!`);
                    }
                }
            }

            if (zombieRides > 0) issues.push(`🧟 ${zombieRides} Fahrten ohne Status`);
            if (stuckPending > 0) issues.push(`🔒 ${stuckPending} Fahrten seit >2h im Status "new" ohne Fahrzeug`);
            if (missingCoords > 0) issues.push(`📍 ${missingCoords} aktive Fahrten ohne Koordinaten`);
            if (missingPrice > 0) issues.push(`💰 ${missingPrice} aktive Fahrten ohne Preis`);

            // ═══════════════════════════════════════
            // 2. FAHRZEUG-STATUS
            // ═══════════════════════════════════════
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            stats.vehicles = Object.keys(vehicles).length;

            for (const [vId, vehicle] of Object.entries(vehicles)) {
                // GPS veraltet (> 24h ohne Update bei "online" Fahrzeug)
                if (vehicle.isOnline && vehicle.lastUpdate) {
                    const gpsAge = now - vehicle.lastUpdate;
                    if (gpsAge > 24 * 3600000) {
                        const hours = Math.round(gpsAge / 3600000);
                        issues.push(`📡 Fahrzeug ${vehicle.name || vId} "online" aber GPS seit ${hours}h veraltet`);
                    }
                }
            }

            // ═══════════════════════════════════════
            // 3. TELEGRAM PENDINGS (hängengebliebene Buchungen)
            // ═══════════════════════════════════════
            const pendingSnap = await db.ref('settings/telegram/pending').once('value');
            const pendings = pendingSnap.val() || {};
            stats.pendings = Object.keys(pendings).length;
            let stalePendings = 0;

            for (const [chatId, pending] of Object.entries(pendings)) {
                const age = pending.createdAt ? (now - pending.createdAt) : 0;
                // Älter als 6 Stunden → wahrscheinlich hängengeblieben
                if (age > 6 * 3600000 || (!pending.createdAt && pending.partial)) {
                    stalePendings++;
                    const name = (pending.partial || {}).name || chatId;
                    const ageH = age ? `${Math.round(age / 3600000)}h` : 'unbekannt';
                    issues.push(`🔒 Telegram-Pending hängt: ${name} (Chat ${chatId}, Alter: ${ageH})`);
                }
            }

            if (stalePendings > 0) {
                issues.push(`📱 ${stalePendings} hängengebliebene Telegram-Buchungen → automatisch bereinigt`);
                // Auto-Cleanup: Pendings > 24h löschen
                for (const [chatId, pending] of Object.entries(pendings)) {
                    const age = pending.createdAt ? (now - pending.createdAt) : 0;
                    if (age > 24 * 3600000) {
                        await db.ref(`settings/telegram/pending/${chatId}`).remove();
                        console.log(`🧹 Stale Pending gelöscht: ${chatId}`);
                    }
                }
            }

            // ═══════════════════════════════════════
            // 4. CRM-DATEN-QUALITÄT
            // ═══════════════════════════════════════
            const customersSnap = await db.ref('customers').once('value');
            const customers = customersSnap.val() || {};
            stats.customers = Object.keys(customers).length;

            let noPhone = 0;
            let noAddress = 0;
            let duplicatePhones = {};

            for (const [cId, cust] of Object.entries(customers)) {
                if (!cust.phone && !cust.mobilePhone) noPhone++;
                if (!cust.address && !cust.street) noAddress++;

                // Telefon-Duplikate finden
                const phones = [cust.phone, cust.mobilePhone].filter(p => p);
                for (const p of phones) {
                    const normalized = String(p).replace(/\D/g, '').slice(-9);
                    if (normalized.length >= 8) {
                        if (!duplicatePhones[normalized]) duplicatePhones[normalized] = [];
                        duplicatePhones[normalized].push(cust.name || cId);
                    }
                }
            }

            const dupes = Object.entries(duplicatePhones).filter(([_, names]) => names.length > 1);
            if (dupes.length > 0) {
                issues.push(`👥 ${dupes.length} mögliche CRM-Duplikate (gleiche Telefonnummer):`);
                dupes.slice(0, 5).forEach(([phone, names]) => {
                    issues.push(`   ↳ ...${phone}: ${names.join(' / ')}`);
                });
                if (dupes.length > 5) issues.push(`   ↳ ...und ${dupes.length - 5} weitere`);
            }

            // ═══════════════════════════════════════
            // 5. RECHNUNGEN PRÜFEN
            // ═══════════════════════════════════════
            const invoicesSnap = await db.ref('invoices').once('value');
            const invoices = invoicesSnap.val() || {};
            let unpaidInvoices = 0;
            let missingPdf = 0;

            for (const [invId, inv] of Object.entries(invoices)) {
                if (inv.status === 'offen' || inv.status === 'open') unpaidInvoices++;
                if (!inv.pdfUrl) missingPdf++;
            }

            if (unpaidInvoices > 0) issues.push(`💶 ${unpaidInvoices} offene/unbezahlte Rechnungen`);
            if (missingPdf > 0) issues.push(`📄 ${missingPdf} Rechnungen ohne PDF`);

            // ═══════════════════════════════════════
            // 6. HEUTIGE FAHRTEN ZUSAMMENFASSUNG
            // ═══════════════════════════════════════
            const todayStart = new Date(today.toLocaleDateString('en-US', { timeZone: 'Europe/Berlin' })).getTime();
            const todayEnd = todayStart + 24 * 3600000;

            let todayRides = 0;
            let todayUnassigned = 0;
            let todayCompleted = 0;

            for (const [rideId, ride] of Object.entries(rides)) {
                const rideTs = ride.pickupTimestamp || ride.createdAt || 0;
                if (rideTs >= todayStart && rideTs < todayEnd) {
                    todayRides++;
                    if (!ride.assignedVehicle && !['completed', 'cancelled', 'deleted'].includes(ride.status)) {
                        todayUnassigned++;
                    }
                    if (ride.status === 'completed') todayCompleted++;
                }
            }

            // ═══════════════════════════════════════
            // 7. ERROR-LOG ZUSAMMENFASSUNG (letzte 24h)
            // ═══════════════════════════════════════
            let errorCount24h = 0;
            let criticalErrors24h = 0;
            let topErrorFunctions = {};
            try {
                const yesterdayKey = new Date(now - 86400000).toISOString().slice(0, 10);
                const todayKey = getTodayLogKey();
                for (const dayKey of [yesterdayKey, todayKey]) {
                    const errSnap = await db.ref(`errorLogs/${dayKey}`).once('value');
                    const errLogs = errSnap.val() || {};
                    for (const [, entry] of Object.entries(errLogs)) {
                        if (entry.t && entry.t > now - 86400000) {
                            errorCount24h++;
                            if (entry.severity === 'critical') criticalErrors24h++;
                            if (entry.fn) {
                                topErrorFunctions[entry.fn] = (topErrorFunctions[entry.fn] || 0) + 1;
                            }
                        }
                    }
                }
                if (errorCount24h > 0) {
                    issues.push(`🔴 ${errorCount24h} Fehler in den letzten 24h (${criticalErrors24h} kritisch)`);
                    // Top-3 Fehlerquellen
                    const topErrors = Object.entries(topErrorFunctions).sort((a, b) => b[1] - a[1]).slice(0, 3);
                    for (const [fn, count] of topErrors) {
                        issues.push(`   ↳ ${fn}: ${count}x`);
                    }
                }
                // ErrorLogs aufräumen (max 7 Tage)
                await trimErrorLogs();
            } catch (e) {
                console.warn('⚠️ ErrorLog-Zusammenfassung fehlgeschlagen:', e.message);
            }

            // ═══════════════════════════════════════
            // BERICHT SENDEN
            // ═══════════════════════════════════════
            const statusEmoji = issues.length === 0 ? '✅' : (issues.length <= 3 ? '⚠️' : '🔴');
            const header = `${statusEmoji} <b>TÄGLICHER SYSTEMBERICHT</b>\n📅 ${todayStr} · 06:00 Uhr\n`;

            const statsBlock = `📊 <b>System-Status:</b>\n` +
                `   🚕 ${stats.rides} Fahrten gesamt\n` +
                `   📅 ${todayRides} Fahrten heute (${todayCompleted} erledigt, ${todayUnassigned} ohne Fahrer)\n` +
                `   🚗 ${stats.vehicles} Fahrzeuge\n` +
                `   👥 ${stats.customers} CRM-Kunden\n` +
                `   📱 ${stats.pendings} aktive Telegram-Buchungen\n` +
                (errorCount24h > 0 ? `   🔴 ${errorCount24h} Fehler (${criticalErrors24h} kritisch)\n` : `   ✅ Keine Fehler in 24h\n`);

            let report;
            if (issues.length === 0) {
                report = header + '\n' + statsBlock + '\n✅ <b>Keine Unstimmigkeiten gefunden!</b>\n\n🎉 System läuft einwandfrei.';
            } else {
                report = header + '\n' + statsBlock +
                    `\n⚠️ <b>${issues.length} Unstimmigkeiten gefunden:</b>\n\n` +
                    issues.map((issue, i) => `${i + 1}. ${issue}`).join('\n') +
                    `\n\n💡 <i>Bitte prüfen und ggf. korrigieren.</i>`;
            }

            // An alle Admins senden
            await sendToAllAdmins(report, 'system_check');
            await sendToSystemChannel(report, 'system_check');

            console.log(`✅ Systemkontrolle abgeschlossen: ${issues.length} Probleme gefunden`);

            // In Firebase loggen
            await db.ref('settings/systemCheck').update({
                lastRun: now,
                issuesCount: issues.length,
                issues: issues.slice(0, 20), // Max 20 speichern
                stats: stats,
                todayRides: todayRides,
                todayUnassigned: todayUnassigned
            });

        } catch (err) {
            console.error('❌ Systemkontrolle Fehler:', err.message, err.stack);
            await logError('dailySystemCheck', err, { severity: 'critical' });
            try {
                await sendToAllAdmins(`❌ <b>Systemkontrolle fehlgeschlagen!</b>\n\nFehler: ${err.message}\n\n<i>Fehlerlog: Firebase → errorLogs</i>`);
            } catch (_) {}
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.44: FEHLERANALYSE-DASHBOARD (HTTP-Endpunkt)
// Zeigt alle Fehler der letzten 7 Tage als JSON oder HTML
// ═══════════════════════════════════════════════════════════════

exports.errorDashboard = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        // Admin-Check (Telegram-Webhook-Secret als Key)
        const key = req.query.key;
        const secretSnap = await db.ref('settings/telegram/webhookSecret').once('value');
        const secret = secretSnap.val();
        if (!key || key !== secret) {
            res.status(403).json({ error: 'Nicht autorisiert. ?key= Parameter fehlt oder falsch.' });
            return;
        }

        const format = req.query.format || 'html';
        const days = Math.min(parseInt(req.query.days) || 3, 7);

        // ErrorLogs laden
        const allErrors = [];
        const now = new Date();
        for (let i = 0; i < days; i++) {
            const d = new Date(now);
            d.setDate(d.getDate() - i);
            const dayKey = d.toISOString().slice(0, 10);
            try {
                const snap = await db.ref(`errorLogs/${dayKey}`).once('value');
                const logs = snap.val() || {};
                for (const [id, entry] of Object.entries(logs)) {
                    allErrors.push({ id, dayKey, ...entry });
                }
            } catch (e) { /* skip */ }
        }

        allErrors.sort((a, b) => (b.t || 0) - (a.t || 0));

        if (format === 'json') {
            res.status(200).json({ total: allErrors.length, days, errors: allErrors.slice(0, 200) });
            return;
        }

        // Statistiken
        const bySeverity = { critical: 0, error: 0, warning: 0, data_inconsistency: 0 };
        const byFunction = {};
        for (const e of allErrors) {
            const sev = e.type === 'data_inconsistency' ? 'data_inconsistency' : (e.severity || 'error');
            bySeverity[sev] = (bySeverity[sev] || 0) + 1;
            const fn = e.fn || e.type || '?';
            byFunction[fn] = (byFunction[fn] || 0) + 1;
        }
        const topFunctions = Object.entries(byFunction).sort((a, b) => b[1] - a[1]).slice(0, 10);

        // HTML
        const html = `<!DOCTYPE html><html lang="de"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Fehleranalyse — Taxi Heringsdorf</title>
<style>
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:20px;background:#1a1a2e;color:#eee}
h1{color:#e94560}h2{color:#fff;background:#0f3460;padding:8px 16px;border-radius:8px;display:inline-block}
.stats{display:flex;gap:16px;flex-wrap:wrap;margin:20px 0}
.stat{background:#16213e;padding:16px;border-radius:12px;min-width:120px;text-align:center}
.stat .num{font-size:2em;font-weight:bold}
.stat.critical .num{color:#e94560}.stat.error .num{color:#ff9800}
.stat.warning .num{color:#ffc107}.stat.data .num{color:#2196f3}
.error-list{margin:20px 0}
.error-item{background:#16213e;padding:12px 16px;border-radius:8px;margin:8px 0;border-left:4px solid #666}
.error-item.critical{border-left-color:#e94560}.error-item.error{border-left-color:#ff9800}
.error-item.warning{border-left-color:#ffc107}.error-item.data_inconsistency{border-left-color:#2196f3}
.meta{color:#888;font-size:.85em}.fn{color:#00d2ff;font-weight:bold}
.msg{color:#ff6b6b;margin:4px 0}
pre{background:#0a0a1a;padding:8px;border-radius:4px;overflow-x:auto;font-size:.8em;color:#888;max-height:100px}
.top-fn{display:flex;gap:8px;flex-wrap:wrap}
.fn-badge{background:#16213e;padding:6px 12px;border-radius:20px;font-size:.85em}
.fn-count{color:#e94560;font-weight:bold}
.refresh{background:#e94560;color:#fff;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-size:1em;margin:10px 0}
</style></head><body>
<h1>🔍 Fehleranalyse-Dashboard v${CLOUD_FUNCTIONS_VERSION}</h1>
<p>Zeitraum: letzte ${days} Tage · ${allErrors.length} Einträge · <button class="refresh" onclick="location.reload()">🔄 Aktualisieren</button></p>
<div class="stats">
<div class="stat critical"><div class="num">${bySeverity.critical}</div>Kritisch</div>
<div class="stat error"><div class="num">${bySeverity.error}</div>Fehler</div>
<div class="stat warning"><div class="num">${bySeverity.warning}</div>Warnungen</div>
<div class="stat data"><div class="num">${bySeverity.data_inconsistency}</div>Daten-Fehler</div>
</div>
<h2>Top Fehlerquellen</h2>
<div class="top-fn">
${topFunctions.map(([fn, count]) => '<span class="fn-badge">' + fn + ': <span class="fn-count">' + count + 'x</span></span>').join('\n')}
</div>
<h2>Fehlerlog (neueste zuerst)</h2>
<div class="error-list">
${allErrors.slice(0, 50).map(e => {
    const sev = e.type === 'data_inconsistency' ? 'data_inconsistency' : (e.severity || 'error');
    const sevIcon = sev === 'critical' ? '🔴' : (sev === 'error' ? '🟠' : (sev === 'warning' ? '🟡' : '🔵'));
    return '<div class="error-item ' + sev + '">' +
'<div class="meta">' + sevIcon + ' ' + (e.ts || new Date(e.t).toLocaleString('de-DE')) + ' · <span class="fn">' + (e.fn || e.type || '?') + '</span>' + (e.chatId ? ' · Chat: ' + e.chatId : '') + (e.rideId ? ' · Ride: ' + e.rideId : '') + '</div>' +
'<div class="msg">' + ((e.msg || (e.issues || []).join(', ') || '?') + '').substring(0, 200) + '</div>' +
(e.stack ? '<pre>' + (e.stack + '').substring(0, 300) + '</pre>' : '') +
(e.data ? '<pre>Kontext: ' + (e.data + '').substring(0, 200) + '</pre>' : '') +
'</div>';
}).join('\n')}
</div>
<p class="meta">JSON: ?format=json&days=${days}&key=... · Max 7 Tage · Auto-Cleanup</p>
</body></html>`;

        res.status(200).send(html);
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.44: ECHTZEIT-KONSISTENZ-PRÜFUNG bei Fahrt-Erstellung
// Prüft sofort ob Strecke/Preis/Koordinaten konsistent sind
// ═══════════════════════════════════════════════════════════════

async function validateRideConsistency(rideId, ride) {
    const issues = [];

    // 1. Koordinaten vorhanden aber kein Preis?
    if (ride.pickupLat && ride.destinationLat && !ride.price && !ride.estimatedPrice) {
        issues.push('Preis fehlt trotz vorhandener Koordinaten');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.price) {
                await db.ref(`rides/${rideId}`).update({
                    price: route.price, estimatedPrice: route.price,
                    distance: route.distance, estimatedDistance: route.distance,
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, '🔧', `Auto-Fix: Preis/Strecke nachberechnet (${route.price}€, ${route.distance} km)`, 'validateRideConsistency');
                issues.push('→ Auto-Fix: ' + route.price + '€, ' + route.distance + ' km berechnet');
            }
        } catch (e) {
            issues.push('→ Preis-Auto-Fix fehlgeschlagen: ' + e.message);
        }
    }

    // 2. Preis vorhanden aber keine Strecke?
    if (ride.price && !ride.distance && !ride.estimatedDistance && ride.pickupLat && ride.destinationLat) {
        issues.push('Strecke fehlt trotz Preis und Koordinaten (genau dein Fall!)');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.distance) {
                await db.ref(`rides/${rideId}`).update({
                    distance: route.distance, estimatedDistance: route.distance,
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, '🔧', `Auto-Fix: Strecke nachberechnet (${route.distance} km, ${route.duration} Min)`, 'validateRideConsistency');
                issues.push('→ Auto-Fix: ' + route.distance + ' km berechnet');
            }
        } catch (e) {
            issues.push('→ Strecke-Auto-Fix fehlgeschlagen: ' + e.message);
        }
    }

    // 3. distance=0 aber estimatedDistance vorhanden → korrigieren
    if ((!ride.distance || ride.distance === 0 || ride.distance === '0') && ride.estimatedDistance && parseFloat(ride.estimatedDistance) > 0) {
        issues.push('distance=0 aber estimatedDistance=' + ride.estimatedDistance + ' vorhanden');
        try {
            await db.ref(`rides/${rideId}`).update({
                distance: parseFloat(ride.estimatedDistance),
                updatedAt: Date.now()
            });
            await addRideLog(rideId, '🔧', 'Auto-Fix: distance=0 -> ' + ride.estimatedDistance + ' km (aus estimatedDistance)', 'validateRideConsistency');
            issues.push('-> Auto-Fix: distance=' + ride.estimatedDistance);
        } catch (e) { /* ignore */ }
    }

    // 3b. price=0 aber estimatedPrice vorhanden → korrigieren
    if ((!ride.price || ride.price === 0 || ride.price === '0') && ride.estimatedPrice && parseFloat(ride.estimatedPrice) > 0) {
        issues.push('price=0 aber estimatedPrice=' + ride.estimatedPrice + ' vorhanden');
        try {
            await db.ref(`rides/${rideId}`).update({
                price: parseFloat(ride.estimatedPrice),
                updatedAt: Date.now()
            });
            await addRideLog(rideId, '🔧', 'Auto-Fix: price=0 -> ' + ride.estimatedPrice + ' (aus estimatedPrice)', 'validateRideConsistency');
            issues.push('-> Auto-Fix: price=' + ride.estimatedPrice);
        } catch (e) { /* ignore */ }
    }

    // 3c. duration falsch niedrig (< 5 Min bei Strecke > 10 km) → Route neu berechnen
    if (ride.pickupLat && ride.destinationLat && ride.estimatedDistance && parseFloat(ride.estimatedDistance) > 10 && ride.duration && parseInt(ride.duration) < 5) {
        issues.push('duration=' + ride.duration + ' Min bei ' + ride.estimatedDistance + ' km Strecke - unrealistisch');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.duration > 5) {
                await db.ref(`rides/${rideId}`).update({
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, '🔧', 'Auto-Fix: duration ' + ride.duration + ' -> ' + route.duration + ' Min (OSRM)', 'validateRideConsistency');
                issues.push('-> Auto-Fix: duration=' + route.duration + ' Min');
            }
        } catch (e) { /* ignore */ }
    }

    // 4. Koordinaten fehlen komplett
    if (!ride.pickupLat && ride.pickup) {
        issues.push('Abholort ohne Koordinaten: "' + ride.pickup + '"');
    }
    if (!ride.destinationLat && ride.destination) {
        issues.push('Zielort ohne Koordinaten: "' + ride.destination + '"');
    }

    // 5. Status-Konsistenz
    if (ride.assignedVehicle && ride.status === 'new') {
        issues.push('Status "new" aber Fahrzeug zugewiesen (' + ride.assignedVehicle + ')');
        // Auto-Fix
        try {
            await db.ref(`rides/${rideId}/status`).set('assigned');
            await addRideLog(rideId, '🔧', 'Auto-Fix: Status new → assigned (Fahrzeug war zugewiesen)');
            issues.push('→ Auto-Fix: Status auf "assigned" gesetzt');
        } catch (e) { /* ignore */ }
    }

    // 5. Datum-Konsistenz
    if (ride.pickupTimestamp) {
        const now = Date.now();
        if (ride.pickupTimestamp < now - 48 * 3600000 && !['completed', 'cancelled', 'deleted'].includes(ride.status)) {
            issues.push('Abholzeit >48h in Vergangenheit aber Status: ' + ride.status);
        }
    }

    if (issues.length > 0) {
        await logDataInconsistency(rideId, ride, issues);
    }

    return issues;
}

// ═══════════════════════════════════════════════════════════════
// HEALTH CHECK — Live-Status für Terminal-Diagnose
// Aufruf: node check.js  ODER  curl "URL?key=SECRET"
// ═══════════════════════════════════════════════════════════════
exports.healthCheck = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        // Key-Check: statischer Health-Check Key (in Firebase settings/healthCheckKey speicherbar)
        const key = req.query.key;
        // Primär: Firebase Datenbank Key; Fallback: statischer Key
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const savedKey = keySnap.val();
        const STATIC_KEY = 'funk-taxi-heringsdorf-2026';
        const validKey = savedKey || STATIC_KEY;
        if (!key || key !== validKey) {
            res.status(403).json({ error: 'Kein Zugriff. ?key= Parameter fehlt. Standard: funk-taxi-heringsdorf-2026' });
            return;
        }

        try {
            const now = Date.now();
            const berlinNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));

            // 1. Fahrzeuge
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            const vehicleStatus = {};
            let onlineCount = 0;
            for (const [id, v] of Object.entries(vehicles)) {
                const isOnline = v.online === true;
                const gpsAge = v.lastUpdate ? Math.round((now - v.lastUpdate) / 60000) : null;
                if (isOnline) onlineCount++;
                vehicleStatus[id] = {
                    name: v.name || id,
                    online: isOnline,
                    gpsAgeMin: gpsAge,
                    gpsStale: gpsAge !== null && gpsAge > 30,
                };
            }

            // 2. Aktive Fahrten
            const ridesSnap = await db.ref('rides').orderByChild('pickupTimestamp')
                .startAt(now - 2 * 3600000).endAt(now + 24 * 3600000).once('value');
            const activeStatuses = ['new', 'assigned', 'vorbestellt', 'accepted', 'picked_up', 'on_way'];
            const rides = { new: [], assigned: [], vorbestellt: [], accepted: [], running: [] };
            ridesSnap.forEach(child => {
                const r = child.val();
                if (r.status === 'new') rides.new.push({ id: child.key, name: r.customerName, pickup: r.pickup });
                else if (r.status === 'assigned') rides.assigned.push({ id: child.key, name: r.customerName });
                else if (r.status === 'vorbestellt') rides.vorbestellt.push({ id: child.key, name: r.customerName, time: r.pickupTime });
                else if (r.status === 'accepted') rides.accepted.push({ id: child.key, name: r.customerName });
                else if (['picked_up', 'on_way'].includes(r.status)) rides.running.push({ id: child.key, name: r.customerName, status: r.status });
            });

            // 3. Telegram Bot
            const webhookActiveSnap = await db.ref('settings/telegram/webhookActive').once('value');
            const pendingSnap = await db.ref('settings/telegram/pending').once('value');
            const pendingCount = Object.keys(pendingSnap.val() || {}).length;

            // 4. Buchungssystem Online?
            const bookingOnlineSnap = await db.ref('settings/bookingSystemOnline').once('value');

            // 5. Schichtplan heute
            const dateStr = berlinNow.toISOString().slice(0, 10);
            const shiftsSnap = await db.ref('vehicleShifts').once('value');
            const shifts = shiftsSnap.val() || {};
            const inShiftToday = [];
            const CAPACITY = { 'pw-ik-222': 4, 'pw-my-222-e': 4, 'pw-ki-222': 4, 'pw-sk-222': 8, 'vg-lk-111': 8, 'pw-ym-222-e': 4 };
            for (const [vid, vShifts] of Object.entries(shifts)) {
                const dayEntry = vShifts[dateStr];
                if (dayEntry && dayEntry.active !== false) inShiftToday.push(vid);
            }

            const status = {
                timestamp: new Date().toISOString(),
                version: CLOUD_FUNCTIONS_VERSION,
                ok: true,
                vehicles: { online: onlineCount, total: Object.keys(vehicles).length, details: vehicleStatus },
                rides: {
                    new: rides.new.length,
                    assigned: rides.assigned.length,
                    vorbestellt: rides.vorbestellt.length,
                    accepted: rides.accepted.length,
                    running: rides.running.length,
                    details: rides
                },
                telegram: {
                    webhookActive: webhookActiveSnap.val(),
                    pendingConversations: pendingCount,
                },
                bookingSystemOnline: bookingOnlineSnap.val(),
                shiftToday: { vehiclesPlanned: inShiftToday.length, vehicleIds: inShiftToday },
                warnings: []
            };

            // Warnungen generieren
            if (onlineCount === 0) status.warnings.push('⚠️ Kein Fahrzeug online!');
            if (rides.new.length > 0) status.warnings.push(`🆕 ${rides.new.length} unbearbeitete Sofortfahrt(en)!`);
            for (const [id, v] of Object.entries(vehicleStatus)) {
                if (v.online && v.gpsStale) status.warnings.push(`📍 ${v.name}: GPS veraltet (${v.gpsAgeMin} Min)`);
            }
            if (!webhookActiveSnap.val()) status.warnings.push('⚠️ Telegram Webhook NICHT aktiv!');
            if (bookingOnlineSnap.val() === false) status.warnings.push('🔴 Buchungssystem ist OFFLINE!');

            if (status.warnings.length === 0) status.warnings.push('✅ Alles OK');
            status.ok = !status.warnings.some(w => w.startsWith('⚠️') || w.startsWith('🆕'));

            res.status(200).json(status);
        } catch (e) {
            res.status(500).json({ error: e.message, ok: false });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.40.8: DRIVER-HEALTH LOG — GPS + Akku-Temperatur auf Abruf
// Endpoint für Claude/Admin um Fahrer-Health zu prüfen
// ?key=XXX&vehicleId=YYY&hours=24 (vehicleId optional → alle)
// ═══════════════════════════════════════════════════════════════
exports.getHealthLog = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const savedKey = keySnap.val();
        const STATIC_KEY = 'funk-taxi-heringsdorf-2026';
        const validKey = savedKey || STATIC_KEY;
        if (!key || key !== validKey) {
            res.status(403).json({ error: 'Kein Zugriff. ?key= Parameter fehlt.' });
            return;
        }

        try {
            const hours = Math.max(1, Math.min(168, parseInt(req.query.hours, 10) || 24));
            const vehicleId = req.query.vehicleId ? String(req.query.vehicleId) : null;
            const since = Date.now() - hours * 3600 * 1000;

            async function loadVehicleHealth(vid) {
                const healthSnap = await db.ref('driverHealth/' + vid)
                    .orderByKey()
                    .startAt(String(since))
                    .once('value');
                const entries = [];
                healthSnap.forEach(c => { entries.push(c.val()); });

                const alertsSnap = await db.ref('driverHealthAlerts/' + vid).limitToLast(50).once('value');
                const alerts = [];
                alertsSnap.forEach(c => {
                    const a = c.val();
                    if (a && a.ts && a.ts >= since) alerts.push(a);
                });

                // Aggregation: min/max/avg Temp, Akku-Verlauf, Sample-Zahl
                let tMin = null, tMax = null, tSum = 0, tN = 0;
                let pctMin = null, pctMax = null;
                for (const e of entries) {
                    if (typeof e.battery_temp_c === 'number' && e.battery_temp_c > -50 && e.battery_temp_c < 100) {
                        if (tMin === null || e.battery_temp_c < tMin) tMin = e.battery_temp_c;
                        if (tMax === null || e.battery_temp_c > tMax) tMax = e.battery_temp_c;
                        tSum += e.battery_temp_c;
                        tN++;
                    }
                    if (typeof e.battery_pct === 'number' && e.battery_pct >= 0) {
                        if (pctMin === null || e.battery_pct < pctMin) pctMin = e.battery_pct;
                        if (pctMax === null || e.battery_pct > pctMax) pctMax = e.battery_pct;
                    }
                }

                return {
                    vehicleId: vid,
                    samples: entries.length,
                    hours: hours,
                    summary: {
                        battery_temp_c: {
                            min: tMin,
                            max: tMax,
                            avg: tN > 0 ? Math.round(tSum / tN * 10) / 10 : null,
                        },
                        battery_pct: { min: pctMin, max: pctMax },
                    },
                    alerts: alerts,
                    latest: entries.length > 0 ? entries[entries.length - 1] : null,
                    // Nur letzte 20 Einträge als Detail — sonst wird die Response riesig
                    recent: entries.slice(-20),
                };
            }

            const result = { ok: true, generatedAt: new Date().toISOString(), hours };

            if (vehicleId) {
                result.vehicles = [await loadVehicleHealth(vehicleId)];
            } else {
                // Alle Fahrzeuge aus /driverHealth
                const allSnap = await db.ref('driverHealth').once('value');
                const vids = [];
                allSnap.forEach(c => { vids.push(c.key); });
                result.vehicles = [];
                for (const vid of vids) {
                    result.vehicles.push(await loadVehicleHealth(vid));
                }
            }

            res.status(200).json(result);
        } catch (e) {
            res.status(500).json({ error: e.message, ok: false });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.96: SMS-QUEUE — Sendet Telegram-Nachricht an Admin
// Macrodroid fängt Telegram-Notification ab → sendet SMS über SIM
// Format: 📲SMS|+49151...|SMS Text hier
// ═══════════════════════════════════════════════════════════════
exports.onSmsQueued = onValueCreated(
    {
        ref: '/smsQueue/{smsId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const smsId = event.params.smsId;
        const smsData = event.data.val();
        if (!smsData || !smsData.phone || !smsData.text) return;
        if (smsData.status !== 'pending') return;

        console.log(`📲 onSmsQueued: ${smsId} — ${smsData.phone} — ${smsData.type}`);

        try {
            // SMS-Chat-ID laden (separater Chat für SMS-Trigger, damit nicht alle Admin-Nachrichten matchen)
            // Fallback: Erster Admin-Chat
            let smsChatId = null;
            const smsChatSnap = await db.ref('settings/sms/telegramChatId').once('value');
            smsChatId = smsChatSnap.val();

            if (!smsChatId) {
                // Fallback: Ersten Admin-Chat verwenden
                const adminSnap = await db.ref('settings/telegram/adminChats').once('value');
                const admins = adminSnap.val();
                if (Array.isArray(admins) && admins.length > 0) smsChatId = admins[0];
                else if (typeof admins === 'object' && admins) smsChatId = Object.values(admins)[0];
                else if (admins) smsChatId = admins;
            }

            if (!smsChatId) {
                console.warn('⚠️ onSmsQueued: Kein Chat-ID konfiguriert');
                await db.ref(`smsQueue/${smsId}`).update({ status: 'failed', error: 'Kein Chat-ID', processedAt: Date.now() });
                return;
            }

            // Zwei separate Telegram-Nachrichten für Macrodroid:
            // 1. Telefonnummer (Macrodroid speichert sie in Variable)
            // 2. SMS-Text (Macrodroid sendet SMS an gespeicherte Nummer)
            await sendTelegramMessage(smsChatId, `📲SMSNUM ${smsData.phone}`, { parse_mode: undefined });
            // 1 Sekunde warten damit Macrodroid die Nummer verarbeiten kann
            await new Promise(r => setTimeout(r, 1000));
            await sendTelegramMessage(smsChatId, `📲SMSTXT ${smsData.text}`, { parse_mode: undefined });

            console.log(`✅ SMS-Trigger via Telegram gesendet: ${smsData.phone}`);

            await db.ref(`smsQueue/${smsId}`).update({
                status: 'telegram_sent',
                sentAt: Date.now(),
                sentTo: smsChatId
            });

        } catch (err) {
            console.error('❌ onSmsQueued Fehler:', err.message);
            await db.ref(`smsQueue/${smsId}`).update({ status: 'failed', error: err.message, processedAt: Date.now() });
        }
    }
);

// ═══════════════════════════════════════════════════════════════
// 🆕 v6.38.96: ANFRAGEN-TRIGGER — Telegram bei neuer Web-Anfrage
// ═══════════════════════════════════════════════════════════════
exports.onAnfrageCreated = onValueCreated(
    {
        ref: '/anfragen/{anfrageId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const anfrageId = event.params.anfrageId;
        const anfrage = event.data.val();
        if (!anfrage) return;

        console.log(`📬 Neue Anfrage: ${anfrageId} — ${anfrage.name || '?'} — ${anfrage.type || 'taxi'}`);

        try {
            const isBerlin = anfrage.type === 'berlin-shuttle';
            const channelIcon = anfrage.channel === 'whatsapp' ? '💬' : '✉️';
            const typeIcon = isBerlin ? '🚐' : '🚕';
            const typeLabel = isBerlin ? 'BERLIN-SHUTTLE' : 'TAXI';

            let message = `${typeIcon} <b>NEUE ${typeLabel}-ANFRAGE!</b> ${channelIcon}\n\n`;
            message += `👤 <b>${anfrage.name || '?'}</b>\n`;
            message += `📱 ${anfrage.phone || '?'}\n`;
            message += `📍 ${anfrage.pickup || '?'}\n`;
            message += `🎯 ${anfrage.destination || '?'}\n`;

            if (isBerlin) {
                message += `📅 Hin: ${anfrage.dateHin || '?'}\n`;
                message += `📅 Rück: ${anfrage.dateReturn || '?'}\n`;
            } else {
                message += `📅 ${anfrage.date || '?'} um ${anfrage.time || '?'}\n`;
            }

            message += `👥 ${anfrage.passengers || '1'} Pers.\n`;
            message += `💰 ${anfrage.price || '?'}\n`;
            message += `\n⚡ <i>Über: ${anfrage.channel === 'whatsapp' ? 'WhatsApp' : 'E-Mail'}</i>`;

            await sendToAllAdmins(message, 'new_ride');
            console.log(`✅ Anfrage-Telegram gesendet: ${anfrageId}`);
        } catch (err) {
            console.error('❌ onAnfrageCreated Fehler:', err.message);
        }
    }
);
